package com.example.jdr_android

import com.example.jdr_android.db.JdrDatabase
import com.example.jdr_android.enums.DamageType
import com.example.jdr_android.enums.DiceType
import com.example.jdr_android.enums.Stat

fun initData(db: JdrDatabase) {

    // --- RACES ---
    if (db.raceQueries.selectAll().executeAsList().isEmpty()) {
        // N'insère que si la BDD est vide — évite les doublons au redémarrage
        db.raceQueries.insert("Demi-Elfe", 0, 0, -2, 0, 2, 0)
        db.raceQueries.insert("Demi-Orque", 2, 0, 0, -2, 0, -2)
        db.raceQueries.insert("Haut Elfe", -2, 0, 0, 0, 0, 2)
        db.raceQueries.insert("Elfe Sylvain", -2, 2, 0, 0, 0, 0)
        db.raceQueries.insert("Gnome", -2, 0, 0, 2, 0, 0)
        db.raceQueries.insert("Halfelin", -2, 2, 0, 0, 0, 0)
        db.raceQueries.insert("Humain", 0, 0, 0, 0, 0, 0)
        db.raceQueries.insert("Nain", 0, -2, 2, 0, 0, 0)
    }

    // --- CAPACITES RACIALES ---
    if (db.racialAbilityQueries.selectAll().executeAsList().isEmpty()) {

        db.racialAbilityQueries.insert(
            "Lumière des étoiles",
            "Pour le personnage, l’obscurité de la nuit sous la lumière des étoiles " +
                    "n’est que de la pénombre, où seuls les petits détails lui échappent."
        )
        db.racialAbilityQueries.insert(
            "Instinct de survie",
            "Lorsqu’une attaque devrait amener le personnage à 0 PV, les DM qu’elle " +
                    "inflige sont divisés par 2 (minimum 1)."
        )
        db.racialAbilityQueries.insert(
            "Vision dans le noir",
            "Dans le noir total, le personnage voit comme dans la pénombre jusqu’à 30 m."
        )
        db.racialAbilityQueries.insert(
            "Don étrange",
            "le personnage possède un talent inné pour les sciences, qu’elles soient " +
                    "occultes ou plus ordinaires.\n" +
                    "Le joueur choisit une des deux options suivantes :\n" +
                    "   - Soit son personnage gagne un bonus de +5 sur tous les tests d’INT ;\n" +
                    "   - Soit il choisit une capacité de rang 1 d’Ensorceleur. Il peut utiliser ce sort " +
                    "sans pénalité avec une armure allant jusqu’à la chemise de maille."
        )
        db.racialAbilityQueries.insert(
            "Petite taille",
            "le personnage obtient un bonus de +1 en DEF et de +2 à tous les tests de " +
                    "discrétion. En revanche, il peut seulement utiliser à une main une arme dont " +
                    "les DM sont au maximum égaux à 1d6 (épée courte, masse, etc.). Il lui faut " +
                    "utiliser les 2 mains pour les armes qui infligent 1d8 à 1d10 de DM (épée " +
                    "longue). Enfin il lui est interdit d’utiliser les armes qui infligent plus de " +
                    "1d10 DM."
        )
    }

    // --- LIENS RACE -> CAPACITES RACIALES
    if (db.racePossessesAbilityQueries.selectAll().executeAsList().isEmpty()) {
        db.racePossessesAbilityQueries.linkRaceToAbility(1, 1)
        db.racePossessesAbilityQueries.linkRaceToAbility(1, 2)
        db.racePossessesAbilityQueries.linkRaceToAbility(2, 3)
        db.racePossessesAbilityQueries.linkRaceToAbility(3, 1)
        db.racePossessesAbilityQueries.linkRaceToAbility(4, 1)
        db.racePossessesAbilityQueries.linkRaceToAbility(5, 4)
        db.racePossessesAbilityQueries.linkRaceToAbility(6, 5)
        db.racePossessesAbilityQueries.linkRaceToAbility(7, 2)
        db.racePossessesAbilityQueries.linkRaceToAbility(8, 3)
    }

    // --- PROFILS ---
    if (db.profileQueries.selectAll().executeAsList().isEmpty()) {
        db.profileQueries.insert("Arquebusier", DiceType.D8.toString())
        db.profileQueries.insert("Barbare", DiceType.D12.toString())
        db.profileQueries.insert("Barde", DiceType.D6.toString())
        db.profileQueries.insert("Chevalier", DiceType.D10.toString())
        db.profileQueries.insert("Druide", DiceType.D8.toString())
        db.profileQueries.insert("Ensorceleur", DiceType.D4.toString())
        db.profileQueries.insert("Forgesort", DiceType.D6.toString())
        db.profileQueries.insert("Guerrier", DiceType.D10.toString())
        db.profileQueries.insert("Magicien", DiceType.D4.toString())
        db.profileQueries.insert("Moine", DiceType.D8.toString())
        db.profileQueries.insert("Nécromancien", DiceType.D4.toString())
        db.profileQueries.insert("Prêtre", DiceType.D8.toString())
        db.profileQueries.insert("Rôdeur", DiceType.D8.toString())
        db.profileQueries.insert("Voleur", DiceType.D6.toString())
    }

    // --- VOIES ---
    if (db.pathQueries.selectAll().executeAsList().isEmpty()) {
        // Arquebusier (1)
        db.pathQueries.insert(1, "Voie de l'artilleur", null)
        db.pathQueries.insert(1, "Voie des explosifs", "Chaque jour l’Arquebusier peut utiliser un nombre de charges explosives égal au Rang dans la voie. Ces charges permettent indifféremment d’utiliser les capacités Démolition, Piège explosif ou Boulet explosif.")
        db.pathQueries.insert(1, "Voie du champ de bataille", null)
        db.pathQueries.insert(1, "Voie du pistolero", null)
        db.pathQueries.insert(1, "Voie de la précision", null)
        // Barbare (2)
        db.pathQueries.insert(2, "Voie de la brute", null)
        db.pathQueries.insert(2, "Voie du pagne", null)
        db.pathQueries.insert(2, "Voie du pourfendeur", null)
        db.pathQueries.insert(2, "Voie du primitif", null)
        db.pathQueries.insert(2, "Voie de la rage", null)
        // Barde (3)
        db.pathQueries.insert(3, "Voie de l'escrime", null)
        db.pathQueries.insert(3, "Voie du musicien", null)
        db.pathQueries.insert(3, "Voie du saltimbanque", null)
        db.pathQueries.insert(3, "Voie de la séduction", null)
        db.pathQueries.insert(3, "Voie du vagabond", null)
        // Chevalier (4)
        db.pathQueries.insert(4, "Voie du cavalier", null)
        db.pathQueries.insert(4, "Voie de la guerre", null)
        db.pathQueries.insert(4, "Voie du héros", null)
        db.pathQueries.insert(4, "Voie du meneur d'hommes", null)
        db.pathQueries.insert(4, "Voie de la noblesse", null)
        // Druide (5)
        db.pathQueries.insert(5, "Voie des animaux", null)
        db.pathQueries.insert(5, "Voie du fauve", null)
        db.pathQueries.insert(5, "Voie de la nature", null)
        db.pathQueries.insert(5, "Voie du protecteur", null)
        db.pathQueries.insert(5, "Voie des végétaux", null)
        // Ensorceleur (6)
        db.pathQueries.insert(6, "Voie de l'air", null)
        db.pathQueries.insert(6, "Voie de la divination", null)
        db.pathQueries.insert(6, "Voie de l'envoûteur", "Si une victime résiste à un sort de cette voie, elle y est immunisée pendant 24h.")
        db.pathQueries.insert(6, "Voie des illusions", null)
        db.pathQueries.insert(6, "Voie de l'invocation", null)
        // Forgesort (7)
        db.pathQueries.insert(7, "Voie des artefacts", null)
        db.pathQueries.insert(7, "Voie des élixirs", "Chaque jour, le Forgesort peut créer jusqu’à deux élixirs par rang acquis dans la Voie. Produire un lot d’élixirs prend une heure, quel qu’en soit le nombre. Ce sont des mélanges instables qui deviennent inopérants après 24h. Le joueur doit donc en noter l’heure de fabrication. Passé 24h, le Forgesort peut régénérer les élixirs en seulement 10 mn, mais ils comptent alors parmi les potions créés pour la journée.")
        db.pathQueries.insert(7, "Voie du métal", null)
        db.pathQueries.insert(7, "Voie du golem", null)
        db.pathQueries.insert(7, "Voie des runes", null)
        // Guerrier (8)
        db.pathQueries.insert(8, "Voie du bouclier", "Pour utiliser les capacités de cette voie, le personnage doit obligatoirement manier un bouclier.")
        db.pathQueries.insert(8, "Voie du combat", null)
        db.pathQueries.insert(8, "Voie du maître d'armes", null)
        db.pathQueries.insert(8, "Voie de la résistance", null)
        db.pathQueries.insert(8, "Voie du soldat", null)
        // Magicien (9)
        db.pathQueries.insert(9, "Voie de la magie des arcanes", null)
        db.pathQueries.insert(9, "Voie de la magie destructrice", null)
        db.pathQueries.insert(9, "Voie de la magie élémentaire", null)
        db.pathQueries.insert(9, "Voie de la magie protectrice", null)
        db.pathQueries.insert(9, "Voie de la magie universelle", "Pour chaque Rang dans cette Voie, le personnage obtient un bonus de +2 aux tests d’INT basés sur la connaissance et l’érudition.")
        // Moine (10)
        db.pathQueries.insert(10, "Voie de l'énergie vitale", null)
        db.pathQueries.insert(10, "Voie de la maîtrise", null)
        db.pathQueries.insert(10, "Voie de la méditation", null)
        db.pathQueries.insert(10, "Voie du poing", null)
        db.pathQueries.insert(10, "Voie du vent", null)
        // Nécromancien (11)
        db.pathQueries.insert(11, "Voie du démon", null)
        db.pathQueries.insert(11, "Voie de la mort", "Les sorts de cette voie n’affectent pas les créatures non vivantes (golem, élémentaires, mort-vivants...).")
        db.pathQueries.insert(11, "Voie de l'outre-tombe", null)
        db.pathQueries.insert(11, "Voie du sang", null)
        db.pathQueries.insert(11, "Voie de la sombre magie", "Le personnage obtient un bonus de +2 par rang à tous les tests d’INT basés sur les connaissances occultes.")
        // Prêtre (12)
        db.pathQueries.insert(12, "Voie de la foi", null)
        db.pathQueries.insert(12, "Voie de la guerre sainte", null)
        db.pathQueries.insert(12, "Voie de la prière", null)
        db.pathQueries.insert(12, "Voie des soins", "Soins légers et soins modérés peuvent être utilisés un nombre de fois par jour égal au Rang que le personnage a atteint dans cette Voie. Au Rang 2 par exemple, il peut utiliser chaque capacité 2 fois par jour.")
        db.pathQueries.insert(12, "Voie de la spiritualité", null)
        // Rôdeur (13)
        db.pathQueries.insert(13, "Voie de l'archer", null)
        db.pathQueries.insert(13, "Voie du compagnon animal", "Le personnage obtient un loup pour compagnon animal dès qu’il prend au moins un Rang dans cette Voie.")
        db.pathQueries.insert(13, "Voie de l'escarmouche", null)
        db.pathQueries.insert(13, "Voie de la survie", null)
        db.pathQueries.insert(13, "Voie du traqueur", null)
//        // Rôdeur/Montreur d'ours (14)
//        db.pathQueries.insert(13, "Voie de l'archer", null)
//        db.pathQueries.insert(13, "Voie du montreur d'ours", "Le personnage obtient un jeune ours noir pour compagnon animal dès qu’il prend au moins un Rang dans cette Voie")
//        db.pathQueries.insert(13, "Voie de l'escarmouche", null)
//        db.pathQueries.insert(13, "Voie de la survie", null)
//        db.pathQueries.insert(13, "Voie du traqueur", null)
        // Voleur (14)
        db.pathQueries.insert(14, "Voie de l'assassin", null)
        db.pathQueries.insert(14, "Voie de l'aventurier", null)
        db.pathQueries.insert(14, "Voie du déplacement", null)
        db.pathQueries.insert(14, "Voie du roublard", null)
        db.pathQueries.insert(14, "Voie du spadassin", null)
    }

    // --- CAPACITES ---
    if (db.skillQueries.selectAll().executeAsList().isEmpty()) {
        // l’Arquebusier
        db.skillQueries.insert("Mécanismes", false, false, 1, "Le personnage obtient un bonus de +1 par Rang dans cette voie à tous les tests visant à réparer ou à comprendre des mécanismes (cela inclut le fait de désamorcer des pièges mécaniques et de manipuler des armes de siège). Il peut appliquer ce bonus à tous les tests d’attaque avec des armes de siège (baliste, couleuvrine, canon, trébuchet, catapulte, etc.).")
        db.skillQueries.insert("Tir de semonce", true, false, 2, "Après avoir raté une attaque à distance au tour précédent, le personnage déclare qu’il s’agissait d’un tir de semonce. À ce tour, il tire sur la même cible et obtient +5 à son test et +1d6 aux DM sur sa première attaque.")
        db.skillQueries.insert("Tir de barrage", true, false, 3, "Le personnage met en joue une cible sur laquelle il a l’Initiative et attend. Si elle se déplace à ce tour, il effectue une attaque à distance. En cas de succès la victime choisit entre deux possibilités : soit elle subit double dégâts, soit elle ne se déplace pas et ne subit pas de dégâts, tout en perdant son tour.")
        db.skillQueries.insert("Couleuvrine", true, false, 4, "L'Arquebusier obtient une couleuvrine, un petit canon portatif qui nécessite la mise en place d’un trépied (ou d’un appui). Utiliser cette arme demande une action limitée et ne peut avoir lieu qu’une seule fois par combat. Sur un test d’attaque à distance réussi, elle inflige [4d6 + Mod. de DEX] DM. La portée maximale de cette arme est de 100 mètres et sa portée minimale de 10 mètres.")
        db.skillQueries.insert("Feu nourri", false, false, 5, "Lorsqu’il utilise le Tir de barrage, le personnage peut affecter jusqu’à [1 + Mod. de DEX] cibles différentes dans le même tour. Toutes les cibles doivent être dans une zone frontale de 20 mètres de large au maximum. Chaque cible donne lieu à un test d’attaque à distance indépendant.")
        db.skillQueries.insert("Chimiste", false, false, 1, "Le personnage sait fabriquer sa propre poudre et d’autres substances explosives, et obtient un bonus de +2 par Rang à tous les tests de chimie ou d’alchimie. Les armes à poudre du personnage ne présentent plus de risque de « faire long feu » ou d’explosion et le joueur ne lance plus de dé de poudre.")
        db.skillQueries.insert("Démolition", false, false, 2, "Le personnage peut préparer un explosif qui lui permet de démolir facilement des structures. Il lui faut 3 tours complets pour préparer et poser son explosif. Celui-ci inflige à la structure 2d6 DM par Rang dans la voie et 1d6 par rang dans un rayon de 6 mètres autour (en ignorant la moitié de la RD de la structure. Voir DM aux structures).")
        db.skillQueries.insert("Poudre puissante", false, false, 3, "Le personnage sait préparer lui-même une poudre plus puissante, il ajoute +10 mètres à la portée et +2 aux dégâts de toutes ses armes à poudre.")
        db.skillQueries.insert("Piège explosif", true, false, 4, "il faut un tour complet au personnage pour installer un piège qui explose dans un rayon de 3 mètres en infligeant 5d6 DM (test de DEX difficulté 15 pour ne subir que la moitié des DM). Le personnage peut choisir entre deux modes de déclenchement, soit avec un retardateur allant de 1 à 10 tours au choix, soit à l’intrusion de toute créature dans une zone d’1 mètre autour du piège. Cette seconde solution demande 1 tour de préparation supplémentaire et un personnage attentif peut détecter et éviter le piège avec un test de SAG difficulté [12 + Mod. d’INT du personnage].")
        db.skillQueries.insert("Boulet explosif", true, false, 5, "Le personnage sait fabriquer et lancer de petites boules de métal munies de poudre et d’une mèche. Un tel projectile a une portée de 20 mètres et explose dans un rayon de 5 mètres en infligeant 5d6 DM, divisé par 2 pour les victimes qui réussissent un test de DEX difficulté [12 + Mod. de DEX du personnage].")
        db.skillQueries.insert("Action concertée", false, false, 1, "Une fois par tour, le personnage peut échanger son Initiative avec un autre personnage volontaire. S’il cède son Initiative à un personnage plus lent, il gagne un bonus de +1 sur ses tests d’attaque à ce tour. Ce bonus passe à +2 au Rang 4 de la voie.")
        db.skillQueries.insert("À couvert", true, false, 2, "Jusqu’à son prochain tour, le personnage divise par 2 les DM dus aux attaques à distance et de zone qu’il reçoit, et peut se déplacer de 20 mètres. Un compagnon du personnage peut profiter de cette aptitude s’il a son accord et reste à son contact.")
        db.skillQueries.insert("Combattant aguerri", false, false, 3, "le personnage peut choisir n’importe quelle capacité de rang 2 d’une voie de personnage de son choix et gagne 3 PV supplémentaires. Il peut choisir une capacité de Rang 1 seulement et gagne alors 6 PV au lieu de 3.")
        db.skillQueries.insert("Combat de masse", false, false, 4, "L'Arquebusier obtient une action de mouvement ou une action d’attaque supplémentaire à chaque tour si le combat implique au moins 10 créatures (en comptant le personnage et ses alliés).")
        db.skillQueries.insert("Constitution héroïque", false, false, 5, "Le personnage augmente son score de CON de +2 et il peut désormais lancer deux d20 à chaque fois qu’un test de CON lui est demandé et conserver le meilleur résultat.")
        db.skillQueries.insert("Plus vite que son ombre", false, false, 1, "Si son arme à poudre est prête (chargée et tenue en main), le personnage peut tirer avec un bonus de +10 à son Initiative.")
        db.skillQueries.insert("Cadence de tir", false, false, 2, "Recharger une pétoire ou un mousquet devient une action de mouvement. Dans le cas d’une arbalète de poing ou d’une arbalète légère, l’action devient gratuite. À partir du Rang 5 dans la voie, il peut recharger deux armes en une seule action.")
        db.skillQueries.insert("Tir double", true, false, 3, "L'Arquebusier est capable de tirer avec une pétoire dans chaque main sans pénalité. Si le personnage décharge simultanément ses deux armes sur la même cible, il fait un seul test à +2 en attaque (mais il lance séparément les DM). Le joueur peut choisir de ne pas réaliser les deux tirs simultanément, afin, par exemple, de pouvoir tirer sur une autre cible s’il tue la première. Dans ce cas, il n’obtient pas de bonus en attaque.")
        db.skillQueries.insert("As de la gâchette", false, false, 4, "Lorsqu’il atteint une DEF de 25 ou plus sur son attaque à distance avec une arme à poudre ou une arbalète, le personnage ajoute +1d6 aux DM de son attaque.")
        db.skillQueries.insert("Dextérité héroïque", false, false, 5, "Le personnage augmente son score de DEX de +2 et il peut désormais lancer deux d20 à chaque fois qu’un test de DEX lui est demandé, et conserver le meilleur résultat.")
        db.skillQueries.insert("Joli coup !", false, false, 1, "Le personnage ignore les pénalités normalement appliquées lorsque la cible est à couvert (généralement -2 à -5).")
        db.skillQueries.insert("Tir précis", false, false, 2, "Le personnage ajoute un bonus de +1 aux DM des armes de tir jusqu’à une portée de [5 x Mod. de DEX]. Ce bonus passe à +2 au Rang 4 de la voie.")
        db.skillQueries.insert("Défaut dans la cuirasse", true, false, 3, "Le personnage passe un tour complet à analyser le point faible de son adversaire et à viser. Au tour suivant, il réalisera ses attaques à distance sur cette cible contre une DEF de [10 + Mod. de DEX de la cible]. Au lieu de cela, le joueur peut choisir d’ignorer la réduction des DM (RD) d’une créature (dans ce cas la DEF n’est pas modifiée).")
        db.skillQueries.insert("Tir parabolique", false, false, 4, "Le personnage est capable de réaliser un tir à longue distance sans pénalité : il double la portée des armes à distance. Il peut aussi tirer jusqu’au triple de la portée indiquée avec une pénalité de -5 en attaque et aux DM. Cette capacité ne modifie pas la portée de Tir précis.")
        db.skillQueries.insert("Tir mortel", false, false, 5, "Pour une attaque à distance, le personnage peut choisir d’utiliser un d12 pour son attaque au lieu du d20 habituel (et il ajoute normalement son score d’attaque). Si l’attaque est réussie, il ajoute +2d6 aux DM.")
        // le Barbare
        db.skillQueries.insert("Argument de taille", false, false, 1, "Le personnage ajoute son Mod. de FOR à son score de PV maximum ainsi qu’à ses tests de CHA et à ceux de ses alliés au contact pour les tests de négociation, de persuasion ou d’intimidation. Allez savoir pourquoi, sa simple présence donne de la force aux arguments de ses alliés…")
        db.skillQueries.insert("Tour de force", false, false, 2, "Le personnage peut temporairement décupler ses ressources physiques pour faire usage d’une force prodigieuse. Il peut ainsi soulever une charge incroyable, briser une épée, tordre des barreaux ou défoncer une porte d’un seul coup de poing. Il obtient un bonus de +10 à son test de FOR, mais cela lui coûte 1d4 PV.")
        db.skillQueries.insert("Attaque brutale", true, false, 3, "Le personnage réalise une attaque au contact avec une pénalité de -2 en attaque et +1d6 au DM. Au Rang 5 de la voie, il peut choisir une pénalité de -5 pour obtenir +2d6 aux DM.")
        db.skillQueries.insert("Briseur d’os", false, false, 4, "Les coups critiques du personnage sont terribles et provoquent des handicaps durables. Le personnage obtient un critique sur 19 et 20 au résultat du d20 en attaque au contact. Lorsqu’il obtient un critique, en plus des DM doublés, il inflige une pénalité de -2 à tous les tests d’attaque, de FOR et de DEX de sa victime. Cette pénalité affecte la cible jusqu’à ce qu’elle soit complètement guérie.")
        db.skillQueries.insert("Force héroïque", false, false, 5, "Le personnage augmente sa valeur de FOR de +2 et il peut désormais lancer deux d20 à chaque fois qu’un test de FOR lui est demandé et garder le meilleur résultat.")
        db.skillQueries.insert("Vigueur", false, false, 1, "Le personnage est un athlète capable de prouesses physiques extraordinaires, il obtient un bonus de +2 par Rang dans la voie aux tests de course, de saut ou d’escalade.")
        db.skillQueries.insert("Peau de pierre", false, false, 2, "Le personnage est particulièrement endurci, il reçoit un bonus de DEF égal à son Mod. de CON.")
        db.skillQueries.insert("Tatouages", false, false, 3, "Le personnage possède un tatouage magique qui améliore ses performances physiques. Au choix : taureau (+5 aux tests de FOR), ours (+5 aux tests de CON), panthère (+5 aux tests de DEX) ou chouette (+5 aux tests de SAG).")
        db.skillQueries.insert("Peau d’acier", false, false, 4, "Le personnage ne sent plus la douleur et ignore les égratignures, il réduit tous les DM subits de 3 points. Il subit toujours au moins 1 point de DM de chaque attaque reçue.")
        db.skillQueries.insert("Constitution héroïque", false, false, 5, "Le personnage augmente son score de CON de +2 et il peut désormais lancer deux d20 à chaque fois qu’un test de CON lui est demandé et conserver le meilleur résultat.")
        db.skillQueries.insert("Réflexes félins", false, false, 1, "Le personnage obtient un bonus de +1 par Rang dans cette voie à son score d’Initiative et à tous les tests de DEX destinés à esquiver (Boule de feu, souffle, pièges, etc.).")
        db.skillQueries.insert("Charge", true, false, 2, "Le personnage se déplace en ligne droite d’au moins 5 mètres (20 mètres au maximum) et effectue une attaque au contact avec un bonus de +2 en attaque et +1d6 aux DM.")
        db.skillQueries.insert("Enchaînement", false, false, 3, "Chaque fois que le personnage réduit un adversaire à 0 PV avec une attaque de contact, il bénéficie d’une action d’attaque gratuite sur un autre adversaire au contact.")
        db.skillQueries.insert("Déchaînement d’acier", true, false, 4, "Le personnage parcourt 10 mètres en ligne droite en dépassant autant d’ennemis qu’il le souhaite. Il porte une attaque à chaque adversaire sur son passage. Il ne peut terminer son déplacement à un endroit occupé par un ennemi.")
        db.skillQueries.insert("Attaque tourbillon", true, false, 5, "Une fois par combat, le personnage tourne sur lui-même en assénant des attaques à toutes les cibles au contact. Il inflige automatiquement des DM correspondant à l’arme utilisée (plus tous les bonus habituels) à toutes les cibles dans un rayon de 5 m autour de lui.")
        db.skillQueries.insert("Proche de la nature", false, false, 1, "Le personnage obtient un bonus de +1 par Rang dans la voie aux tests de survie, de discrétion ou d’observation en milieu naturel.")
        db.skillQueries.insert("Armure de vent", false, false, 2, "Le personnage obtient un bonus en DEF égal à son Rang dans la voie lorsqu’il ne porte aucune armure.")
        db.skillQueries.insert("Vigilance", false, false, 3, "Le personnage possède des sens très affûtés, il est difficile de le surprendre, il gagne un bonus de +5 à tous les tests pour détecter les pièges (mécaniques ou magiques) ou les embuscades. Il devient immunisé aux Attaques sournoises d’un personnage, à l’Embuscade d’un personnage ou à toute capacité similaire d’une créature.")
        db.skillQueries.insert("Résistance à la magie", false, false, 4, "Le personnage devient capable de résister à la magie. Lorsqu’il est la cible d’un sort, une fois par tour, il peut faire un test d’attaque magique (Mod. de SAG) opposé à celui du sort. En cas de réussite, il n’en subit pas les effets.")
        db.skillQueries.insert("Vitalité débordante", false, false, 5, "Le personnage guérit à une vitesse presque surnaturelle. Tant qu’il lui reste au moins 1 PV, il récupère 1d6 PV par heure, de nuit comme de jour.")
        db.skillQueries.insert("Cri de guerre", true, false, 1, "Une fois par combat, le personnage pousse un hurlement qui effraie ses adversaires. Tout ennemi dont la FOR et les PV maximum sont inférieurs à ceux du personnage subit un malus de -2 à ses tests d’attaque au contact contre le personnage pour le reste du combat. Cette capacité ne nécessite plus qu’une action de mouvement à partir du rang 4.")
        db.skillQueries.insert("Défier la mort", false, false, 2, "Lorsque le personnage subit des DM d’une attaque qui devrait l’amener à 0 PV, il peut réaliser un test de CON difficulté 10. En cas de réussite, il conserve 1 PV. La difficulté augmente de 10 à chaque blessure supplémentaire reçue par la suite. S’il est enragé il obtient un bonus de +10 à ces tests.")
        db.skillQueries.insert("Rage du berserk", true, false, 3, "Le personnage entre dans une rage berserk pour le reste du combat, ce qui le rend particulièrement dangereux. Il obtient un bonus de +2 en attaque et +1d6 aux DM sur toutes ses attaques au contact, mais perd 4 en DEF et ne peut fuir ou attaquer à distance. S’il veut stopper la rage avant d’avoir éliminé tous les ennemis sur le terrain, le personnage doit réussir un test de SAG difficulté 13 (un seul essai par tour).")
        db.skillQueries.insert("Même pas mal", false, false, 4, "Lorsqu’il subit un coup critique, cela a pour effet de décupler la rage du barbare. Il peut immédiatement entrer en Rage ou en Furie (action gratuite), et gagne un bonus de +1d6 aux DM de ses attaques au contact pour les 3 prochains tours. Le joueur note les DM supplémentaires de l’attaque critique à part : le personnage ne perdra ces PV qu’à la fin de la rage.")
        db.skillQueries.insert("Furie du berserk", true, false, 5, "Au lieu de la Rage du berserk, le personnage peut entrer s’il le souhaite en Furie du berserk, qui lui donne +3 en attaque et +2d6 aux DM pour une pénalité en DEF de -6. La difficulté du test de SAG pour sortir prématurément de cet état passe à 16.")
        // le Barde
        db.skillQueries.insert("Précision", false, false, 1, "Le personnage peut utiliser son score d’attaque à distance pour combattre au contact lorsqu’il emploie une arme à une main légère comme une dague, une épée courte ou une rapière.")
        db.skillQueries.insert("Intelligence du combat", false, false, 2, "Le personnage ajoute son Mod. d’INT en Initiative et en DEF en plus de son Mod. de DEX.")
        db.skillQueries.insert("Feinte", true, false, 3, "Le personnage effectue une attaque fictive pour déséquilibrer son adversaire et réaliser ensuite une attaque mortelle. Faites un test d’attaque normal à ce tour mais n’infligez aucun dégât. Au tour suivant, si vous attaquez le même adversaire, vous profiterez d’un bonus de +5 en attaque et, si votre feinte était réussie, de +2d6 aux DM.")
        db.skillQueries.insert("Attaque flamboyante", true, false, 4, "Le style de combat du personnage est flamboyant et surprenant : avec cette Capacité, il effectue une attaque de contact avec un bonus d’attaque et de DM égal à son Mod. de CHA (en plus du Mod. de FOR ou de DEX).")
        db.skillQueries.insert("Botte mortelle", false, false, 5, "Lors d’une attaque au contact, s’il obtient un score total d’attaque supérieur ou égal à la DEF de son adversaire +10 points, le personnage obtient un bonus de +2d6 aux DM de son attaque.")
        db.skillQueries.insert("Chant des héros", true, false, 1, "Le barde chante et inspire ses compagnons : tous les alliés à portée de voix obtiennent un bonus de +1 à tous leurs tests pendant [5+ Mod. de CHA] tours.")
        db.skillQueries.insert("Attaque sonore", true, true, 2, "Le barde pousse un cri dont les effets sont dévastateurs (ou produit un son avec un instrument à cette même fin). Sur un test d’attaque magique réussi, il inflige [1d6 + Mod. de CHA] DM à toutes les cibles lui faisant face sur une portée de 10 m.")
        db.skillQueries.insert("Zone de silence", true, true, 3, "Le personnage crée une zone de silence fixe de 5 mètres de diamètre, jusqu’à une portée de 30 mètres, pendant [1d6+Mod. de CHA] tours. Tous les sons émis dans cette sphère sont annulés. La zone n’empêche pas le lancement des sorts mais inflige un malus de -2 à tous les tests d’attaque magique.")
        db.skillQueries.insert("Danse irrésistible", true, true, 4, "Le barde joue une gigue endiablée aux effets magiques. S’il réussit un test d’attaque magique contre la créature qu’il cible, celle-ci se met à danser pendant [1d4+Mod. de CHA] tours et subit un malus de -4 aux tests d’attaque et en DEF.")
        db.skillQueries.insert("Musique fascinante", true, true, 5, "Le personnage joue de la musique pour fasciner et «contrôler» toutes les créatures de son choix (rats, gobelins, humains, etc.) dans un rayon de 30 m. Seules les créatures dont les PV sont inférieurs ou égaux à [5 + Mod. de CHA] du personnage répondent. Les créatures sortent de leur cachette et se dirigent vers le personnage, elles le suivent tant qu’il continue à jouer. Quand il utilise cette capacité le personnage peut également se déplacer de 10 m par tour.")
        db.skillQueries.insert("Acrobate", false, false, 1, "Le personnage obtient un bonus de +2 par rang à tous ses tests de DEX visant à réaliser des acrobaties, tenir en équilibre, faire des sauts ou de l’escalade.")
        db.skillQueries.insert("Grâce féline", false, false, 2, "Le personnage ajoute son Mod. de CHA en DEF et en Initiative (en plus du Mod. habituel de DEX).")
        db.skillQueries.insert("Lanceur de couteau", false, false, 3, "Une fois par tour, en plus de ses autres actions, le personnage peut lancer un couteau sur une cible à distance (maximum 10 m) en réussissant un test d’Attaque à Distance. Cette attaque est pour lui une action gratuite. Elle occasionne [1d4 + Mod. de DEX] de DM.")
        db.skillQueries.insert("Esquive acrobatique", false, false, 4, "Une fois par tour, le personnage peut réaliser une esquive en réussissant un test d’Attaque à Distance contre une Difficulté égale au score obtenu par son adversaire lors de son attaque. En cas de réussite, le personnage ne subit aucun DM. Si cette attaque était un critique, il subit tout de même des DM normaux (et annule donc l’effet critique «dégâts doublés»).")
        db.skillQueries.insert("Liberté d’action", false, false, 5, "Le barde est immunisé à la peur et à tous les sorts ou effets magiques qui asservissent l’esprit ou le corps (possession, charme, paralysie, ralentissement, etc.).")
        db.skillQueries.insert("Charmant", false, false, 1, "Le personnage obtient un bonus de +2 par rang atteint dans cette voie pour tous ses tests de CHA visant à séduire, baratiner ou mentir.")
        db.skillQueries.insert("Dentelles et rapière", false, false, 2, "Le personnage ne met pas d’armure, cela ne sied point en société. Sa seule armure est la dentelle, sa seule défense, la rapière. Lorsqu’il ne porte aucune armure et combat avec une rapière ou une épée, le personnage obtient un bonus de +1 en DEF contre les attaques au contact par Rang possédé dans cette Voie.")
        db.skillQueries.insert("Arme secrète", false, false, 3, "Une fois par combat, le personnage peut utiliser un subterfuge de séducteur pour surprendre et déstabiliser un adversaire du sexe opposé. Ce peut être un baiser fougueux soudainement délivré au cœur d’une mêlée, un sein qui s’échappe d’un bustier par mégarde, une main qui s’égare par le plus grand des hasards… Il doit réussir un test de CHA de difficulté égale à l’INT de son adversaire. En cas de succès celui-ci subit un malus de -10 en attaque et en DEF pendant 1 tour.")
        db.skillQueries.insert("Suggestion", true, true, 4, "Une fois par jour, le personnage peut suggérer une action à une créature en réussissant un test d’attaque magique avec pour difficulté les PV maximum de celle-ci. En cas de réussite la créature fera tout son possible pour satisfaire sa demande pendant 24 heures. Elle évitera les actions suicidaires (ce qui lui donnerait immédiatement un test d’INT difficulté 10 pour échapper au sort).")
        db.skillQueries.insert("Charisme héroïque", false, false, 5, "Le personnage augmente sa valeur de CHA de +2. Il peut de plus lancer deux d20 à chaque fois qu’un test de CHA lui est demandé et conserver le meilleur résultat.")
        db.skillQueries.insert("Rumeurs et légendes", false, false, 1, "A force de voyager, le personnage a appris toutes sortes de choses, il obtient un bonus de +2 par Rang dans cette voie aux tests d’INT pour se «souvenir» d’une information historique, politique, géographique ou occulte qui pourrait lui être utile.")
        db.skillQueries.insert("Compréhension des langues", true, true, 2, "Ce sort permet au personnage de lire, écrire et parler n’importe quelle langue ancienne ou vivante pendant [1d6 + Mod. de CHA] minutes.")
        db.skillQueries.insert("Débrouillard", false, false, 3, "Le personnage obtient un bonus de +5 à tous ses tests de survie en nature et aux tests de profession et d’artisanat (forge, charpentier, etc.).")
        db.skillQueries.insert("Déguisement", true, true, 4, "Ce sort permet au personnage de prendre l’apparence de n’importe quelle créature de taille à peu près équivalente (avec une marge d’environ 50 cm). S’il veut imiter une personne en particulier, il lui faudra réussir un test de CHA difficulté 15 (20 s’il ne la connaît pas mais l’a seulement vue, 10 s’il la connaît très bien). Le sort a une durée de 10 minutes.")
        db.skillQueries.insert("Touche à tout", false, false, 5, "Le personnage peut choisir n’importe quelle capacité de Rang 1 à 3 de son choix au sein d’un autre Profil de Chroniques Oubliées")
        // le Chevalier
        db.skillQueries.insert("Fidèle monture", false, false, 1, "Le personnage possède un puissant destrier, c’est un cheval de guerre bien dressé qui comprend les ordres simples. À cheval, il peut ajouter un déplacement de 10 m avant ou après une action normale (par exemple faire 10 m et une action limitée). La monture n’attaque que si elle est elle-même attaquée au contact par une créature. Fidèle monture : FOR +4, DEX +0, CON +4, INT -2, SAG +0, CHA +0, Init 10, DEF 13, PV 15, Ruade +5, DM 1d6+4")
        db.skillQueries.insert("Cavalier émérite", false, false, 2, "Lorsqu’il est en selle, le personnage gagne un bonus de +2 en attaque au contact, et sa monture obtient une DEF égale à celle du personnage. Monter ou descendre de cheval est désormais une action gratuite.")
        db.skillQueries.insert("Monture magique", false, false, 3, "Le chevalier obtient une monture magique, qui peut apparaître et disparaître depuis un autre plan à volonté. Il peut l’invoquer à tout moment (c’est une action limitée) et elle apparaît alors pour se mettre à son service. Lorsqu’il la laisse au moins une heure dans son plan d’origine, elle guérit l’ensemble de ses PV.")
        db.skillQueries.insert("Charge", true, false, 4, "A cheval, le chevalier peut effectuer un déplacement de 40 m en ligne droite, et une attaque de contact placée au moment son choix. Il doit parcourir au moins 10 m avant d’attaquer, mais peut réaliser le reste du déplacement à sa guise. Le joueur lance deux d20 à son test d’attaque et garde le meilleur résultat, tout en ajoutant +1d6 aux DM. Une créature située sur la trajectoire de la charge doit réussir un test de FOR difficulté 18 ou être contrainte de céder le passage en subissant 1d6 DM. Si elle réussit ce test, la Charge est bloquée et le tour du personnage se termine.")
        db.skillQueries.insert("Monture fantastique", false, false, 5, "Le chevalier obtient une monture volante (pégase, griffon, hippogriffe, drake, etc.). Init 15, DEF 16, PV [5 × niveau], Att +8, DM 1d6+4. Lorsqu’il est en selle, le chevalier peut faire attaquer sa monture une fois par tour (action gratuite), à la même Initiative que lui, avec un score d’attaque égal à son niveau +3. En vol, la monture couvre une distance de 30 m par action de mouvement. Les capacités de la #Monture magique s’appliquent également.")
        db.skillQueries.insert("Armure sur mesure", false, false, 1, "L’armure du personnage est parfaitement ajustée, aussi il n’ajoute que la moitié de sa DEF à la difficulté des tests pour lesquels l’armure inflige une pénalité (de même pour les casques). Si vous n’utilisez pas la règle de pénalité des armures, le chevalier obtient un bonus de +1 en DEF lorsqu’il porte une armure métallique.")
        db.skillQueries.insert("Encaisser un coup", true, false, 2, "Le chevalier se place de façon à dévier un coup sur son armure. À son tour, il fait seulement une action d’attaque ou une action de mouvement. Par la suite, à tout moment avant son prochain tour, il peut retrancher aux dégâts subits suite à une attaque au contact un total égal au Mod. de DEF de son armure (plus d’éventuels bonus de magie et de bouclier).")
        db.skillQueries.insert("Coup de bouclier", false, false, 3, "Le chevalier peut effectuer à chaque tour une attaque au bouclier avec un d12 au lieu du d20 (action gratuite) qui inflige [1d4 + Mod. de FOR] DM.")
        db.skillQueries.insert("Frappe lourde", true, false, 4, "Le chevalier effectue une attaque au contact avec 1d12 au lieu du d20 (en ajoutant normalement son score d’attaque). Si l’attaque est réussie, il ajoute +2d6 aux DM. Il ignore la moitié de la réduction des DM de la créature (RD), si elle possède cette capacité.")
        db.skillQueries.insert("Force héroïque", false, false, 5, "Le personnage augmente sa valeur de FOR de +2 et il peut désormais lancer deux d20 à chaque fois qu’un test de FOR lui est demandé et garder le meilleur résultat.")
        db.skillQueries.insert("Ignorer la douleur", false, false, 1, "Une fois par combat, le personnage peut noter à part les DM subis par une attaque. Il n’en subira les effets que lorsque le combat sera terminé.")
        db.skillQueries.insert("Piqures d’insecte", false, false, 2, "Lorsqu’il porte une armure lourde (demi-plaque ou plus), le personnage réduit les DM subis par les attaques à distances d’un montant égal au rang atteint dans cette voie.")
        db.skillQueries.insert("Laissez-le-moi !", false, false, 3, "Le chevalier met un point d’honneur à combattre le leader ennemi. Lorsqu’il peut aisément être identifié dans un groupe d’au moins 4 créatures, le personnage lui inflige +1d6 DM par attaque.")
        db.skillQueries.insert("Seul contre tous", true, false, 4, "Le chevalier sait faire face à de nombreux adversaires, en tentant de profiter d’une éventuelle faille dans leur garde. Chaque fois qu’un des adversaires l’attaque, il bénéficie d’une action d’attaque immédiate contre celui-ci (valable même si la créature l’attaque plusieurs fois).")
        db.skillQueries.insert("Charisme héroïque", false, false, 5, "Le personnage augmente sa valeur de CHA de +2. Il peut de plus lancer deux d20 à chaque fois qu’un test de CHA lui est demandé et conserver le meilleur résultat.")
        db.skillQueries.insert("Sans peur", false, false, 1, "Le personnage est immunisé aux attaques de peur et il offre un bonus de [2 + Mod. de CHA] à tous ses alliés contre ce type d’effet.")
        db.skillQueries.insert("Intercepter", false, false, 2, "Une fois par tour, le personnage peut encaisser un coup à la place d’un allié à ses cotés. Il utilise sa DEF plutôt que celle de la cible initiale et retranche aux DM son rang dans la voie.")
        db.skillQueries.insert("Exemplaire", false, false, 3, "Une fois par tour, le personnage permet à un allié qui combat le même adversaire que lui de relancer le d20 d’un test d’attaque, s’il s’agissait d’un d’échec.")
        db.skillQueries.insert("Ordre de bataille", false, false, 4, "Le chevalier donne des ordres tactiques pertinents au cœur de la bataille. Une fois par tour, il octroie une action supplémentaire gratuite à un allié en vue (une action de mouvement ou une action d’attaque, mais pas une action limitée).")
        db.skillQueries.insert("Charge fantastique", true, false, 5, "Une fois par combat, à l’Initiative du personnage, lui-même et tous ses alliés en vue bénéficient immédiatement d’un déplacement d’un maximum de 20 m en ligne droite, suivi d’une action d’attaque avec un bonus de +3 au test de réussite et +1d6 aux dégâts. Résolvez d’abord tous les déplacements en commençant par le personnage, puis par ordre d’Initiative. Ensuite effectuez toutes les attaques dans le même ordre.")
        db.skillQueries.insert("Éduqué", false, false, 1, "Le personnage sait lire et écrire, il gagne +1 par rang dans la voie à tous les tests d’INT et de CHA.")
        db.skillQueries.insert("Autorité naturelle", false, false, 2, "Le chevalier obtient un bonus égal à [1 + Mod. de CHA] en Initiative et en DEF. De plus, il bénéficie d’un bonus de +5 aux tests de CHA réalisés pour donner des ordres ou intimider.")
        db.skillQueries.insert("Écuyer", false, false, 3, "Le personnage dispose d’un écuyer à son service (Initiative 14, Défense 14, PV 13, Att +3, DM 1d8+1). Il est absolument loyal à son maître et lui sert de serviteur, il s’occupe de sa monture et de son équipement, prépare le campement, panse les blessures, etc. Grâce à l’écuyer, les armes du personnage sont parfaitement affûtées et infligent des critiques sur 19 ou 20. De plus, le personnage, sa monture et jusqu’à [1 + Mod. de CHA] alliés récupèrent 2d6 PV supplémentaires chaque nuit s’ils profitent des services de l’écuyer. Tous les frais sont pris en charge par la capacité. Si l’écuyer vient à mourir, le personnage en prendra un autre à son service au niveau suivant.")
        db.skillQueries.insert("Massacrer la piétaille", false, false, 4, "Le personnage ajoute +1d6 aux DM contre la piétaille. S’il y a au moins 4 créatures aux statistiques semblables impliquées dans le combat, elles sont assimilées à de la piétaille (même si leur nombre est par la suite réduit à moins de 4 au cours du combat). Les grandes créatures et les cavaliers ne sont jamais considérés comme de la piétaille.")
        db.skillQueries.insert("Formation d’élite", false, false, 5, "Le chevalier possède les moyens et la culture nécessaire pour obtenir une formation dans n’importe quel domaine qui lui sied. Choisissez une capacité de rang 1 à 3 dans n’importe quel Profil issu de la famille des combattants ou des voyageurs.")
        // le Druide
        db.skillQueries.insert("Langage des animaux", false, false, 1, "Le personnage peut communiquer avec les animaux qui, en général, se comportent avec lui de manière amicale. Il gagne un bonus de +2 par rang à tous les tests destinés à influencer un animal. La communication reste primitive et limitée à l’intelligence de l’animal et à son point de vue (prédateur, proie, etc.).")
        db.skillQueries.insert("Nuée d’insectes", true, true, 2, "En réussissant un test d’attaque magique (portée 20 m), le personnage libère sur sa cible une nuée d’insectes volants qui piquent, aveuglent et la suivent pendant [5 + Mod. de SAG] tours. La victime subit 1 point de DM par tour et un malus de -2 à toutes ses actions. Les DM de zone détruisent la nuée.")
        db.skillQueries.insert("Le guetteur", false, false, 3, "Le personnage reçoit un oiseau de proie comme compagnon animal. Il possède un lien télépathique avec lui et peut percevoir par ses sens avec un bonus de +5 aux tests basés sur la perception. Aigle : DEF 15, PV [il les partage avec ceux de son maître]. Attaque de contact = [attaque magique du druide], DM 1d4.")
        db.skillQueries.insert("Masque du prédateur", true, true, 4, "Lorsqu’il est sous l’effet de ce sort, le personnage prend les traits d’un fauve ou d’un loup. Il gagne son Mod. de SAG en Initiative, en attaque et aux DM et peut voir dans la nuit (comme un elfe) pendant [5 + Mod. de SAG] tours.")
        db.skillQueries.insert("Forme animale", true, true, 5, "Le personnage peut prendre la forme d’un animal d’une taille inférieure ou égale à la sienne. Il conserve ses PV, il acquiert les Carac. et les capacités naturelles de la forme choisie (le vol pour un oiseau, la respiration aquatique pour le poisson, etc.). Le personnage peut reprendre sa forme humaine lorsqu’il le désire (L).")
        db.skillQueries.insert("Vitesse du félin", false, false, 1, "Le personnage gagne +1 par rang dans la voie en Initiative et aux tests de course, d’escalade ou de saut.")
        db.skillQueries.insert("Panthère", false, false, 2, "Le personnage apprivoise une panthère (ou un puma) qui lui obéit au doigt et à l’œil. Panthère : FOR +2, DEX +4*, CON +2, INT -3, SAG +2*, CHA -2, Init 18, DEF 16, PV [niveau x 4], Attaque au contact [niveau du druide], DM 1d6+2")
        db.skillQueries.insert("Attaque bondissante", true, false, 3, "Le personnage parcourt jusqu’à 30 m et bénéficie d’un bonus de +5 au test d’attaque et de +1d6 aux DM contre sa cible. Il doit se déplacer d’au minimum 5 m en ligne droite pour faire cette attaque, qui ne peut par ailleurs être réalisée qu’à son premier tour du combat.")
        db.skillQueries.insert("Grand félin", false, false, 4, "La panthère devient un animal fabuleux, ou est remplacée par un félin plus grand (tigre, lion). Lorsque le personnage atteint le niveau 8, les DM passent à 2d6+5. Au niveau 12, le félin peut utiliser Attaque bondissante. Le personnage peut également communiquer avec son félin par télépathie, et le guérir à distance en dépensant ses propres PV (-1 PV au personnage par PV octroyé au félin). : FOR +5, DEX +4*, CON +5, INT -3, SAG +2*, CHA -2, DEF 18, DM 1d6+5")
        db.skillQueries.insert("Les sept vies du chat", false, false, 5, "Cette capacité ne peut être utilisée que sept fois, et pas plus d’une fois par niveau. Lorsque les PV du personnage tombent à 0 ou qu’il meurt, le personnage peut choisir d’ignorer ce qui a provoqué la mort ! Le MJ et le joueur doivent se mettre d’accord et trouver une raison plausible (ou pas !) pour expliquer la survie du personnage, et le faire réapparaître immédiatement ou un peu plus tard dans l’aventure si nécessaire.")
        db.skillQueries.insert("Maître de la survie", false, false, 1, "Le personnage obtient un bonus de +2 par rang dans la voie à tous les tests basés sur la survie en milieu naturel (survie, vigilance, discrétion, etc.).")
        db.skillQueries.insert("Marche sylvestre", false, false, 2, "Non seulement le personnage ne subit aucune pénalité de déplacement en terrain difficile (neige, boue, broussailles, pente abrupte, etc.) mais en plus, il obtient un bonus de +2 en attaque et en DEF lors d’un combat dans ces conditions.")
        db.skillQueries.insert("Résistant", false, false, 3, "Le personnage obtient une réduction de DM égal à son [Rang x 2] contre toutes les sources de dégâts « naturels » : froid, chaleur, chutes, poisons… mais aussi aux DM provoqués par les animaux ou les insectes (même géants).")
        db.skillQueries.insert("Bâton de druide", true, false, 4, "Le personnage combat avec les deux extrémités de son bâton de bois noueux. Lorsqu’il utilise cette capacité, il effectue deux attaques de contact infligeant [1d6 DM + Mod. de FOR ou de DEX] (au choix) par attaque.")
        db.skillQueries.insert("Constitution héroïque", false, false, 5, "Le personnage augmente son score de CON de +2 et il peut désormais lancer deux d20 à chaque fois qu’un test de CON lui est demandé et conserver le meilleur résultat.")
        db.skillQueries.insert("Baies magiques", true, true, 1, "Le personnage doit se trouver devant un buisson ou un arbre vivant. Son incantation fait pousser [1d6 + Mod. de SAG] fruits qu’il peut cueillir. Chaque fruit offre l’équivalent d’un repas et rend [1d6 + niveau du druide] PV à celui qui le consomme. Les effets de ces fruits ne fonctionnent qu’une fois par jour et par personnage.")
        db.skillQueries.insert("Forêt vivante", true, true, 2, "La forêt s’éveille dans un rayon d’1 km par rang et devient une alliée du personnage pendant les 12 prochaines heures. Dans ce périmètre, les ennemis du personnage sont désorientés et gênés par les branches et les racines. Ils divisent leur déplacement par deux et subissent une pénalité de -5 en Initiative et à tous les tests de survie, d’orientation, de perception ou de discrétion. Si deux personnages essayent d’influencer la forêt, c’est celui dont le niveau est le plus élevé qui l’emporte.")
        db.skillQueries.insert("Régénération", true, true, 3, "La cible touchée par le personnage guérit 3 PV par tour pendant [niveau du personnage + Mod. de SAG] tours. Ce sort ne peut pas affecter une créature plus d’une fois par jour.")
        db.skillQueries.insert("Forme d’arbre", true, true, 4, "Une fois par combat, le personnage peut se transformer en arbre de petite taille (environ 4 m de hauteur) pendant [5 + Mod. de SAG] tours. Il prend les mêmes Caractéristiques que l’arbre animé, mais conserve ses propres PV. Sous cette forme, il ne peut pas parler mais peut utiliser les sorts des voies du protecteur et des végétaux. Arbre animé : Init 7, DEF 13, PV [rang x 10], attaque de contact = [niveau du druide], DM 1d6+3, Déplacement 10 m par action de mouvement. Réduction de DM de 10 sauf contre les armes tranchantes et le feu.")
        db.skillQueries.insert("Sagesse héroïque", false, false, 5, "Le personnage augmente sa valeur de SAG de +2. Il peut désormais lancer deux d20 à chaque fois qu’un test de SAG lui est demandé et conserver le meilleur résultat.")
        db.skillQueries.insert("Peau d'écorce", false, false, 1, "La peau du personnage prend la consistance de l’écorce. Il gagne +1 en DEF par rang dans la voie pendant [5 + Mod. de SAG] tours.")
        db.skillQueries.insert("Prison végétale", true, true, 2, "Le personnage peut commander à la végétation de pousser et bloquer ses ennemis (mais pas ses alliés) dans une zone de 10 m de diamètre (portée 20 m) pendant [5 + Mod. de SAG] tours. Entravées, les cibles subissent un malus de -2 en attaque et en DEF, et ne peuvent pas se déplacer. Chaque tour, une créature peut se libérer avec un test de FOR difficulté [10 + Mod. de SAG].")
        db.skillQueries.insert("Animation d'un arbre", true, true, 3, "Une fois par combat, le personnage peut animer un arbre en le touchant. Il combat pendant [niveau du druide] tours. Arbre animé : Init 7, DEF 13, PV [rang x 10], attaque de contact = [niveau du druide], DM 1d6+3, Déplacement 10 m par action de mouvement. Réduction de DM de 10 sauf contre les armes tranchantes et le feu.")
        db.skillQueries.insert("Gland de pouvoir", true, true, 4, "Une fois par combat, le personnage peut lancer un gland sur une cible (portée 10 m). En cas d’attaque magique réussie, la victime se transforme en statue de bois pendant [2d6 + Mod. de SAG] tours. Sous cette forme elle ne peut agir et ne ressent rien. Sa DEF passe à 10 mais elle gagne une réduction des DM de 10. Le sort s’achève dès que la cible perd plus de 10 PV.")
        db.skillQueries.insert("Porte végétale", true, true, 5, "Une fois par jour, le personnage peut pénétrer dans le tronc d’un gros arbre et sortir de celui d’un autre arbre appartenant à la même forêt et situé à une distance maximum de [Mod. de SAG] x 10 km.")
        // l’Ensorceleur
        db.skillQueries.insert("Murmures dans le vent", true, true, 1, "Le personnage chuchote un message d’une dizaine de mots qui voyage jusqu’à son destinataire. Il peut entendre sa réponse immédiatement. La portée est de 100 m par Rang dans la voie et le personnage doit connaître la cible ou la voir.")
        db.skillQueries.insert("Sous tension", true, true, 2, "Le personnage se charge d’énergie électrique pour [5 + Mod. de CHA] tours. Toute créature qui le blesse ou le touche reçoit une décharge infligeant 1d6 DM. Il peut également délivrer une décharge électrique (attaque magique, portée 10 m) infligeant [1d6 + Mod. de CHA] DM.")
        db.skillQueries.insert("Télékinésie", true, true, 3, "Le personnage peut déplacer dans les airs un objet inerte ou une cible volontaire (par exemple lui-même) dont le poids n’excède pas 50 kg par Rang, à une portée de 20 m et pendant [5+Mod. de CHA] tours. L’objet peut être déplacé de 10 m par tour au prix d'une action de mouvement. Il est possible de faire tomber un objet sur une cible surprise (DM 1d6 tous les 50 kg).")
        db.skillQueries.insert("Foudre", true, true, 4, "Le personnage produit un éclair sur une ligne de 10 mètres. Toutes les créatures sur la trajectoire sont soumises à un test d’attaque magique et subissent [4d6 + Mod. de CHA] DM en cas de réussite. Les victimes peuvent tenter un test de DEX difficulté [12 + Mod. de DEX] pour ne subir que la moitié des DM.")
        db.skillQueries.insert("Forme éthérée", true, true, 5, "Le personnage et tout son équipement deviennent translucides et intangibles pendant [5 + Mod. de CHA] tours. Sous cette forme, il peut passer à travers murs et obstacles, et ne peut subir aucun DM physiques.")
        db.skillQueries.insert("6ème sens", false, false, 1, "Le personnage sait toujours légèrement en avance ce qui va arriver. Il gagne un bonus de +1 par Rang dans la Voie en Initiative et en DEF, ainsi qu’un bonus de +2 par Rang à tous les tests pour éviter d’être surpris.")
        db.skillQueries.insert("Détection de l’invisible", true, true, 2, "Pendant [5 + Mod. de CHA] tours, le personnage détecte les créatures invisibles ou cachées à moins de 30 mètres et détecte si un sort de Clairvoyance affecte l’endroit. Aveuglé, ce sort lui permet de voir normalement.")
        db.skillQueries.insert("Clairvoyance", true, true, 3, "Le personnage peut voir et entendre à distance ce qui se passe dans un lieu qu’il connait, tant qu’il reste concentré (action limitée à chaque tour). Les créatures présentes ont droit à un test de SAG difficulté [12 + Mod. de CHA] : en cas de réussite, elles se sentent observées.")
        db.skillQueries.insert("Prescienc", false, true, 4, "Une fois par combat, à la fin d’un tour, le joueur peut décider que tout ce qui s’est passé durant ce tour n’était que la vision d’un futur possible. On rejoue alors le tour depuis le début : les autres personnages ne peuvent pas changer leurs actions, contrairement au personnage qui bénéficie d’un bonus de +10 en Initiative et en DEF.")
        db.skillQueries.insert("Hyperconscience", false, false, 5, "Le personnage augmente ses valeurs de SAG et d’INT de +2. Il peut désormais lancer deux d20 à chaque fois qu’un test de SAG ou d’INT lui est demandé et garder le meilleur résultat.")
        db.skillQueries.insert("Injonction", true, true, 1, "Le personnage donne un ordre simple (mais pas dangereux pour elle) que la victime doit pouvoir comprendre. Il doit réussir un test d’attaque magique opposé avec la cible (contre attaque au contact si la créature n'en a pas) à une portée de 20 mètres. En cas d’échec, la cible exécutera l’ordre pendant son prochain tour.")
        db.skillQueries.insert("Sommeil", true, true, 2, "Plonge dans l'inconscience des créatures vivantes pendant [5 + Mod. de CHA] minutes. Affecte un nombre de PV égal au test d'attaque magique de l'Ensorceleur dans une zone de 10 m de diamètre (portée 20 m). Toutes les cibles doivent être d'un Niveau inférieur ou égal à la moitié du Niveau du personnage. Il est possible de les réveiller en les giflant (action d’attaque).")
        db.skillQueries.insert("Confusion", true, true, 3, "En réussissant un test d’Attaque magique (portée 20 m), le personnage désoriente sa cible pendant [3 + Mod. de CHA] tours. Chaque tour, lancer 1d6 : 1-3 la victime n’agit pas, 4-6 elle attaque la créature la plus proche (au hasard). Chaque fin de tour, elle fait un test de SAG difficulté [10 + Mod. de CHA] pour mettre fin au sort.")
        db.skillQueries.insert("Amitié", true, true, 4, "Si le personnage réussit un test d’Attaque magique (portée 10 m) contre le score max de PV d’une cible humanoïde, celle-ci se comporte comme un ami de longue date tant qu’elle n’est pas attaquée. Elle peut résister au sort avec un test de SAG difficulté [12 + Mod. de CHA], renouvelable une fois par jour.")
        db.skillQueries.insert("Domination", true, true, 5, "En réussissant un test d’Attaque magique (portée 20 m) en opposition contre un test d’Attaque magique de la cible (ou d’Attaque au contact si la créature n’en a pas), le personnage prend contrôle de son esprit pendant [1d4 + Mod. CHA] minutes. Son propre corps devient inactif. La victime peut résister au sort avec un test de SAG difficulté [10 + Mod. de CHA] à chaque fois qu’elle subit des DM. Si la créature meurt pendant la domination, le personnage réintègre son corps et subit 1d6 DM.")
        db.skillQueries.insert("Image décalée", true, true, 1, "Pendant [5 + Mod. de CHA] tours, lorsqu’une attaque le touche, le personnage lance 1d6 : sur 5-6, il ne subit pas les DM.")
        db.skillQueries.insert("Mirage", true, true, 2, "Le personnage crée une illusion visuelle et sonore immobile d’une durée de [5 + Mod. de CHA] minutes (ou tours si l’illusion est animée). Le volume maximum de l’illusion est de 10 m de coté par rang dans la voie (portée 500 m). Divisez ces paramètres par 10 si l’illusion est animée. Interagir avec l’illusion la fait disparaître.")
        db.skillQueries.insert("Imitation", true, true, 3, "L'ensorceleur peut prendre l’apparence d’une créature de taille proche (+ ou - 50 cm) qu’il voit au moment de l’incantation. Durée [5 + Mod. de CHA] minutes. Toucher le personnage (une attaque ou non) met fin au sort.")
        db.skillQueries.insert("Dédoublement", true, true, 4, "Sur une Attaque magique réussie (portée 20 m), le personnage crée un double translucide de la cible pendant [5 + Mod. de CHA] tours. Le double est sous le contrôle du personnage. Il possède les mêmes Caractéristiques que l’original mais seulement la moitié de ses PV et tous les DM qu’il inflige sont divisés par deux. Il disparaît si ses PV tombent à 0. Une créature ne peut être dédoublée qu’une fois par combat.")
        db.skillQueries.insert("Tueur fantasmagorique", true, true, 5, "Ce sort invoque les pires terreurs d’une créature vivante et lui fait croire à sa propre mort. Le personnage doit réussir un test d’Attaque magique (portée 20 m) en opposition à un test d’Attaque magique de la cible (ou attaque au contact si la créature n’en a pas). La victime fait un test de SAG difficulté [10 + Mod. de CHA] pour résister. En cas d’échec, elle tombe à 0 PV. En cas de succès, elle perd l’équilibre et tombe par terre. Une créature ne peut être la cible de ce sort qu’une fois par jour, et le personnage ne peut pas affecter un personnage ou une créature de niveau supérieur au sien.")
        db.skillQueries.insert("Familier", false, false, 1, "Le personnage choisit un petit animal (corbeau, chat, furet, serpent…). Il peut utiliser les sens de son familier et communiquer avec lui à distance illimitée. Il gagne de plus +2 en Initiative lorsque son familier est en vue. Familier : DEF [personnage], Init [personnage], PV [il les partage avec ceux de son maître], ils forment une cible unique pour les attaques de zone. FOR -4, DEX +3, CON 0, INT -2, SAG +1, CHA -2.")
        db.skillQueries.insert("Serviteur invisible", true, true, 2, "Ce sort crée une force invisible pendant [5 + Mod. de CHA] minutes. Le serviteur peut effectuer à distance des tâches simples ne nécessitant pas de test de réussite et aucun score de Caractéristique supérieur à 10 (portée 20 m).")
        db.skillQueries.insert("Mur de force", true, true, 3, "Le personnage crée un mur de force indestructible (portée 10 m, maximum 5 m de haut et 10 m de long), ou bien une hémisphère de 3 m de rayon centrée sur lui-même. Le sort dure pendant [5 + Mod. de CHA] tours.")
        db.skillQueries.insert("Arme dansante", true, true, 4, "Le sort crée une lame d’énergie lumineuse pendant [5 + Mod. de CHA] tours. Dès le premier tour, le personnage peut lui ordonner d’attaquer une cible de son choix (action gratuite, portée 20 m). L’attaque magique de la lame = attaque magique du personnage, [1d8 + Mod de CHA] DM.")
        db.skillQueries.insert("Charisme héroïque", false, false, 5, "Le personnage augmente sa valeur de CHA de +2. Il peut de plus lancer deux d20 à chaque fois qu’un test de CHA lui est demandé et conserver le meilleur résultat.")
        // le Forgesort
        db.skillQueries.insert("Bâton de mage", false, false, 1, "Le personnage crée un grand bâton magique. Avec cette arme à deux mains, il gagne un bonus de +1 aux tests d’attaque au contact et inflige [1d6+Mod. d’INT] DM magiques. A partir du rang 3, au prix d’une action limitée, il peut utiliser son score d’attaque magique pour une attaque au contact et infliger [2d6 + Mod. d’INT] DM dans un éclair d’énergie !")
        db.skillQueries.insert("Blocage", true, true, 2, "Le personnage scelle une porte ou un coffre pour une durée en minutes égale à sa valeur d’INT. Seul un mot de commande qu’il choisit permet d’ouvrir l’objet. Celui-ci peut toujours être brisé par la force, mais il bénéficie d’un bonus de +5 en solidité et en RD (réduction des DM) pour toute la durée du sort.")
        db.skillQueries.insert("Sac sans fond", false, false, 3, "Le personnage possède un sac dans lequel il peut entreposer 50 kg de matériel par rang dans la voie, tandis que le sac semble toujours ne peser qu’un kilo. Le sac ne fonctionne pas si on tente d’y mettre une créature vivante. Le sac est de plus capable de fournir au personnage les objets qu’il désire. Il peut en retirer une pelle, une corde, une épée ou tout objet dont la valeur ne dépasse pas 20 pa, le poids 50 kg, la circonférence 1 m et le volume 1 m3. Pas plus de 20 pa de valeur d'objet créés par le sac sans fond ne peuvent exister simultanément. Ces objets ont hélas la propriété de disparaître au bout d’une heure. De ce fait, la nourriture magique retirée du sac ne nourrit pas vraiment celui qui la consomme.")
        db.skillQueries.insert("Frappe des arcanes", true, true, 4, "Le personnage frappe le sol de son bâton et provoque une onde dévastatrice dans un rayon de 10 m autour de lui. Toutes les créatures dans la zone subissent automatiquement [2d6 + Mod. d’INT] DM et doivent réussir un test de FOR difficulté [10 + Mod. d’INT] pour ne pas tomber au sol.")
        db.skillQueries.insert("Artéfact majeur", false, false, 5, "Le personnage peut enchanter des objets. Il peut créer une arme qui donne un bonus de +1 aux tests d’attaque et aux DM ou une armure qui donne un bonus de +1 en DEF et réduit le malus d’encombrement d’autant. Le bonus passe à +2 lorsque le personnage atteint le niveau 8 puis augmente de +1 tous les 3 niveaux (+5 au niveau 17). Il faut un mois de travail et la dépense de 100 po par point de bonus pour créer l’objet. A la fin, le personnage doit réaliser un test d’INT difficulté [10 + 3 x bonus de l’objet] avec un bonus égal au rang atteint dans la Voie du métal. En cas d’échec, l’objet n’est pas enchanté et il faut recommencer (l’argent est perdu !). En cas de succès, le personnage doit insuffler un peu d’énergie vitale dans l’objet : il sacrifie 1 PV qu’il perd définitivement sur son score de PV maximum.")
        db.skillQueries.insert("Fortifiant", false, false, 1, "Un breuvage étrange qui guérit [1d4 + rang] PV et permet de gagner un bonus de +3 aux [rang +1] prochains tests de réussite effectués (dans une limite de temps de 12 heures).")
        db.skillQueries.insert("Feu grégeois", false, false, 2, "Le personnage lance la fiole à une distance maximum de 10 m, grâce à une action d’attaque (réussite automatique). Le contenu explose dans un rayon de 3 m en infligeant 1d6 DM par rang dans la voie. Un test de DEX difficulté [10 + Mod. d’INT] réussi permet aux victimes de diviser les DM par 2.")
        db.skillQueries.insert("Élixir de guérison", false, false, 3, "Le personnage peut préparer un élixir qui soigne [3d6 + Mod. d’INT] PV ou un empoisonnement.")
        db.skillQueries.insert("Potion magique", false, false, 4, "Le personnage peut préparer une potion d’Agrandissement, de Forme gazeuse, de Protection contre les éléments, d’Armure de mage ou de Chute ralentie.")
        db.skillQueries.insert("Élixirs magique", false, false, 5, "Le personnage peut préparer une potion d’Invisibilité, de Vol, de Respiration aquatique, de Flou ou de Hâte.")
        db.skillQueries.insert("Forgeron", false, false, 1, "Le personnage obtient un bonus de +2 par Rang dans la Voie aux tests d’orfèvrerie ou de forge. Au prix d’une action de mouvement, il peut enflammer son marteau ou son bâton pour une durée de [5 + Mod. d’INT] tours et gagne alors un bonus aux DM de +1 par rang dans la voie avec cette arme (DM de feu).")
        db.skillQueries.insert("Métal brûlant", true, true, 2, "Le personnage doit réussir un test d’attaque magique (portée 20 m) pour faire chauffer un objet métallique que sa cible transporte pendant [5 + Mod. d’INT] tours. S’il s’agit d’une arme, elle inflige 1 point de DM par tour à son porteur et un malus de -2 aux tests d’attaque. S’il s’agit d’une armure, elle inflige 1d4 DM par tour à son porteur. La victime peut se débarrasser précipitamment de son armure au prix d’une action limitée.")
        db.skillQueries.insert("Magnétisme", true, true, 3, "Le personnage contrôle le magnétisme autour de lui pendant [3 + Mod. d’INT] tours. Il gagne un bonus de +5 en DEF et divise par 2 les DM de toutes les armes ou projectiles métalliques.")
        db.skillQueries.insert("Métal hurlant", true, true, 4, "Sur un test d’attaque magique réussi, le personnage déforme une pièce d’équipement métallique portée par sa cible. Une arme devient inutilisable et bonne pour le rebut, une armure inflige une pénalité de -5 à tous les tests de son porteur. La victime peut se débarrasser de son armure au prix d’une action limitée. Si l’objet est magique, le sort ne fait effet que 1d4 tours et ne peut viser à nouveau l’objet pour 24 heures. Appliqué à une structure (par exemple une porte blindée), ce sort inflige 4d6 DM en divisant par 2 sa RD (réduction des DM).")
        db.skillQueries.insert("Endurer", false, false, 5, "Le personnage est habitué aux travaux et à la chaleur de la forge. Il réduit tous les DM de feu subits de 5 points et augmente sa valeur de CON de +2. Il peut désormais lancer deux d20 à chaque fois qu’un test de CON lui est demandé, en gardant le meilleur résultat.")
        db.skillQueries.insert("Grosse tête", false, false, 1, "Le personnage remplace la force brutale par un peu de réflexion. Il peut effectuer un test d’INT au lieu d’un test de FOR (exemple : il utilise un levier pour déplacer une lourde charge). Il obtient un bonus de +2 par rang dans la voie à tous les tests de bricolage ou de science.")
        db.skillQueries.insert("Golem", false, false, 2, "Le golem est une créature humanoïde fabriquée par le personnage pour lui servir de serviteur et de garde du corps. Golem : Créature non-vivante, Init [forgesort], DEF 14, PV [4 x niveau], Attaque [niveau + Mod. de FOR], DM 1d8+1. FOR +1, DEX -1, CON +10, INT -4, SAG -3, CHA -4. Le personnage peut réparer le golem au rythme de [1d6 par rang + Mod. d’INT] PV par heure.")
        db.skillQueries.insert("Protecteur", false, false, 3, "Une fois par tour, s’il est au contact d’un personnage, le golem peut s’interposer et subir les DM d’une attaque à sa place.")
        db.skillQueries.insert("Golem supérieur", false, false, 4, "Le personnage peut améliorer son golem en choisissant une option parmi : \n    Armure : +5 en DEF ; \n    Félin : +3 Mod. de DEX ;\n    Baliste : portée 20 m, 2d6 DM ;\n    Taille : +10 PV et +1 Mod. de FOR ;\n    Vol : des « sauts » de 40 m en action limitée ;\n    Cerveau amélioré : +2 Mod. d’INT, SAG, CHA, doué de parole ;\n    Puissant : +2 Mod. de FOR ;\n    Arme à deux mains : +1d8 aux DM au contact.\n    Le joueur peut choisir une option de plus lorsque son personnage atteint les niveaux 9, 13 et 17. Les options peuvent être choisies plusieurs fois et cumulées.")
        db.skillQueries.insert("Intelligence héroïque", false, false, 5, "Le personnage augmente sa valeur d’INT de +2 et il peut désormais lancer deux d20 à chaque fois qu’un test d’INT lui est demandé et conserver le meilleur résultat.")
        db.skillQueries.insert("Runes de défense", false, false, 1, "Le personnage inscrit des runes de protection sur l’ensemble de son équipement et parfois jusque sur sa peau. Il obtient un bonus de +1 en DEF par rang dans la voie.")
        db.skillQueries.insert("Rune d’énergie", true, true, 2, "En réalisant un rituel de 5 minutes, le forgesort enchante un bijou pour 24 h. Celui-ci permet de relancer un d20 une fois par combat sur un test d’attaque, de FOR, DEX ou CON. Un seul bijou de ce type peut être porté.")
        db.skillQueries.insert("Rune de protection", true, true, 3, "En réalisant un rituel de 5 minutes, le personnage enchante une armure pour 24 h. Celle-ci permet d’ignorer les DM d’une attaque une fois par combat.")
        db.skillQueries.insert("Rune de puissance", true, true, 4, "En réalisant un rituel de 5 minutes, le personnage enchante une arme pour 24 h. Celle-ci permet d’infliger les DM maximum une fois par combat.")
        db.skillQueries.insert("Rune de pouvoir", false, false, 5, "Le personnage peut lier un sort à un objet par une inscription runique. S’il ne connaît pas lui-même le sort, il doit se faire aider par un personnage qui sait le lancer. Le sort ainsi lié peut être utilisé trois fois par jour. Le processus est le même que pour fabriquer une arme ou une armure magique, remplacez le bonus par le rang du sort à lier. Il peut aussi lier certains sorts à une potion (en général les sorts dont le personnage lui-même est la cible), mais pas au-delà de son rang dans la Voie des élixirs, au prix de un jour de travail et 10 pa par rang du sort. Le PV perdu pour la création d’une potion est récupéré dès que la potion est consommée ou au plus tard après 1 an.")
        // Le Guerrier
        db.skillQueries.insert("Protéger un allié", false, false, 1, "Le personnage accorde le Mod. de DEF de son bouclier à un compagnon de son choix qui se trouve juste à côté de lui (il conserve ce bonus pour lui-même aussi). Il peut changer de compagnon à chaque tour durant sa phase d’Initiative. C’est une action gratuite.")
        db.skillQueries.insert("Absorber un coup", true, false, 2, "A son tour, le personnage fait seulement une action d’attaque ou de déplacement. Par la suite, à tout moment avant son prochain tour, le personnage peut effectuer un test d’attaque au contact en opposition à un test réussi d’attaque au contact ou à distance d’un adversaire. En cas de réussite, l’attaque adverse est bloquée par le bouclier.")
        db.skillQueries.insert("Absorber un sort", true, false, 3, "A son tour, le personnage fait seulement une action d’attaque ou de déplacement. Par la suite, à tout moment avant son prochain tour, le personnage peut effectuer un test d’attaque magique (Mod. de SAG) en opposition à un test d’attaque magique qui le visait. En cas de réussite, le sort est absorbé par le bouclier et n’a aucun effet sur le personnage.")
        db.skillQueries.insert("Armure lourde", false, false, 4, "Le personnage peut porter une Armure de Plaque. Celle-ci lui confère une DEF de +7 et le protège des attaques critiques (vous subissez des DM normaux au lieu des DM doublés).")
        db.skillQueries.insert("Renvoi de sort", true, false, 5, "Le personnage peut décider de renvoyer un sort qu’il vient d’absorber grâce à sa capacité Absorber un sort. Au lieu d’être annulé, le sort absorbé le tour précédent est retourné contre son expéditeur : le lanceur du sort subit alors les effets de sa propre attaque !")
        db.skillQueries.insert("Vivacité", false, false, 1, "Le personnage gagne +3 en Initiative.")
        db.skillQueries.insert("Désarmer", true, false, 2, "Le personnage réalise une attaque au contact et sa victime doit faire un test d’attaque opposé. Si le personnage obtient le plus haut score, l’arme de son adversaire tombe au sol (une action de mouvement doit être employée pour la ramasser). Si le personnage réussit son test avec au moins 10 points de plus que son adversaire, il empêche celui-ci de récupérer son arme (en posant le pied dessus, en l’envoyant hors de portée, etc.). Cette capacité est évidemment sans effet sur les armes naturelles (griffes, crocs, épine dorsale, etc.). Les adversaires qui utilisent des armes à 2 mains sont plus difficiles à désarmer, infligeant un malus de -5 au test.")
        db.skillQueries.insert("Double attaque", true, false, 3, "Le personnage peut tenter deux attaques au contact durant ce tour avec un malus de -2.")
        db.skillQueries.insert("Attaque circulaire", true, false, 4, "Le personnage peut tenter une attaque au contact contre chaque adversaire engagé au contact avec lui.")
        db.skillQueries.insert("Attaque puissante", false, false, 5, "Le personnage peut choisir d’utiliser 1d12 en attaque au contact au lieu du d20 habituel (il ajoute normalement son score d’attaque). Si une telle attaque est réussie, il ajoute +2d6 aux DM. Cette capacité peut être utilisée avec Double attaque, Attaque circulaire ou Attaque parfaite par exemple.")
        db.skillQueries.insert("Arme de prédilection", false, false, 1, "Le personnage choisit une arme de prédilection (par exemple épée longue ou hache à 1 main, arc court, etc.), et gagne +1 en attaque lorsqu’il l’utilise.")
        db.skillQueries.insert("Science du critique", false, false, 2, "Le personnage inflige des critiques sur 19-20 (18-20 lorsqu’il emploie une rapière ou une Vivelame).")
        db.skillQueries.insert("Spécialisation", false, false, 3, "Lorsque le personnage emploie son arme de prédilection, il gagne un bonus de +2 aux DM.")
        db.skillQueries.insert("Attaque parfaite", true, false, 4, "Lancez deux d20 en attaque au contact et gardez le meilleur résultat, ajoutez +1d6 aux DM.")
        db.skillQueries.insert("Riposte", false, false, 5, "En plus de ses actions normales, une fois par tour, lorsqu’un adversaire rate une attaque de contact contre le personnage, le joueur obtient une attaque supplémentaire contre cet adversaire.")
        db.skillQueries.insert("Robustesse", false, false, 1, "En prenant cette capacité, le personnage gagne 3 PV supplémentaires au Rang 1, puis 3 PV de plus au Rang 3 de cette Voie et enfin 3 PV au Rang 5.")
        db.skillQueries.insert("Armure naturelle", false, false, 2, "Le personnage a endurci son corps. Il bénéficie d’un bonus de +2 à la DEF. Ce bonus passe à +4 lorsqu’il atteint le rang 4 de la voie.")
        db.skillQueries.insert("Second souffle", true, false, 3, "Une fois par combat, le personnage peut décider de ne pas attaquer lors du tour de combat pour reprendre son souffle. Il récupère alors [1d10 + niveau + Mod. de CON] PV.")
        db.skillQueries.insert("Dur à cuire", false, false, 4, "Le personnage reçoit un bonus de +5 à tous ses tests de CON. De plus, lorsqu’il tombe à 0 PV, il peut continuer à agir pendant un ultime tour avant de tomber inconscient.")
        db.skillQueries.insert("Constitution héroïque", false, false, 5, "Le personnage augmente son score de CON de +2 et il peut désormais lancer deux d20 à chaque fois qu’un test de CON lui est demandé et conserver le meilleur résultat.")
        db.skillQueries.insert("Posture de combat", false, false, 1, "Au début de votre tour, choisissez d’appliquer jusqu’à -1 par rang en attaque, en DEF ou aux DM et obtenez l’équivalent en bonus au choix en attaque, en DEF ou aux DM jusqu’à votre prochain tour.")
        db.skillQueries.insert("Combat en phalange", false, false, 2, "Lorsque vous combattez la même créature qu’un allié, vous gagnez +1 en attaque et en DEF par allié au contact avec vous et avec la créature.")
        db.skillQueries.insert("Prouesse", false, false, 3, "Le personnage réussit souvent des exploits physiques hors-norme. Une fois par tour, vous pouvez sacrifier 1d4 PV pour obtenir +5 sur un test de FOR ou de DEX. Vous pouvez annoncer l’utilisation de cette capacité après avoir pris connaissance du résultat du test de Caractéristique.")
        db.skillQueries.insert("Dernier rempart", true, false, 4, "Le personnage effectue uniquement une attaque au contact durant ce tour. En contrepartie, il bénéficie d’une attaque supplémentaire contre tout ennemi qui se déplace à son contact. Un adversaire blessé par cette attaque voit son déplacement stoppé.")
        db.skillQueries.insert("Force héroïque", false, false, 5, "Le personnage augmente sa valeur de FOR de +2 et il peut désormais lancer deux d20 à chaque fois qu’un test de FOR lui est demandé et garder le meilleur résultat.")
        // le Magicien
        db.skillQueries.insert("Agrandissement", true, true, 1, "Le personnage ou une cible volontaire (au contact) voit sa taille augmenter de 50% pendant [5 + Mod. d’INT] tours. Il gagne +2 aux DM au contact et aux tests de FOR. Pataud, il subit un malus de -2 aux tests de DEX.")
        db.skillQueries.insert("Forme gazeuse", true, true, 2, "Le personnage prend la consistance d’un gaz. Il se déplace au ras du sol (s’il chute, il le fait au ralenti) à une vitesse de 10 m par tour. Il peut s’introduire par les plus petits interstices (comme sous une porte) mais ne peut utiliser aucune capacité sous cette forme. Il ne subit pas non plus de DM, à l’exception des sorts de zone occasionnant des DM (comme Boule de feu). Le sort a une durée de [1d4 + Mod. d’INT] tours.")
        db.skillQueries.insert("Hâte", true, true, 3, "Pendant [1d6 + Mod. d’INT] tours, le personnage voit son métabolisme s’accélérer. A partir du tour suivant, il obtient une action supplémentaire par tour : soit une attaque normale, soit une action de mouvement. En revanche, il ne peut toujours accomplir qu’une seule action limitée par tour.")
        db.skillQueries.insert("Téléportation", true, true, 4, "Le personnage disparaît et réapparaît à un autre endroit situé à moins de [INT x 10] mètres. Le lieu d’arrivée doit être soit en ligne de vue, soit parfaitement connu par le personnage.")
        db.skillQueries.insert("Désintégration", true, true, 5, "Le personnage projette un rayon mortel dont la portée est de 20 mètres et qui annule la cohésion de la matière, ne laissant derrière lui qu’un amas de poussière. Un test d’attaque magique réussi permet de toucher une créature et d’infliger [5d6 + Mod. d’INT] DM. Si le magicien vise un objet porté par une créature, le jet d’attaque subit un malus de -5. Les objets magiques sont insensibles à ce sort, les objets normaux sont réduits en poussière. Aucun objet de plus de 50 kg ne peut être affecté par ce sort : inutile donc de tenter de creuser un tunnel par ce biais. En revanche, vous pourrez ainsi désintégrer une porte (ou même une pierre dans un mur).")
        db.skillQueries.insert("Projectile magique", true, true, 1, "Le personnage choisit une cible visible située à moins de 50 mètres. Elle encaisse automatiquement 1d4 points de dégâts (pas de test d’attaque nécessaire). À partir du Rang 4 dans cette Voie, les DM passent à 1d6.")
        db.skillQueries.insert("Rayon affaiblissant", true, true, 2, "Le personnage choisit une cible située à moins de 10 mètres. Si son attaque magique réussit, le rayon affecte la cible qui subit un malus de -2 à ses tests de FOR, d’attaque au contact et de dégâts, pendant [1d6 + Mod. d’INT] tours.")
        db.skillQueries.insert("Flèche enflammée", true, true, 3, "Le personnage choisit une cible située à moins de 30 mètres. Si son attaque magique réussit, la cible encaisse [1d6 + Mod. d’INT] DM et la flèche enflamme ses vêtements. Chaque tour de combat suivant, le feu inflige 1d6 dégâts supplémentaires. Sur un résultat de 1 à 2, les flammes s’éteignent et le sort prend fin.")
        db.skillQueries.insert("Boule de feu", true, true, 4, "Le personnage choisit une cible située à moins de 30 mètres. Il fait un test d’attaque magique et le compare à la DEF de tous les personnages (y compris le personnage et ses compagnons) se trouvant dans un rayon de 6 mètres autour de la cible. Chaque victime pour laquelle le test est un succès encaisse [4d6 + Mod. d’INT] de DM et doit effectuer un test de DEX difficulté 10 + Mod. d’INT du personnage pour ne subir que la moitié des DM. Quand le test d’attaque est un échec, la cible subit automatiquement la moitié des DM (pas besoin de faire le test de DEX).")
        db.skillQueries.insert("Rituel de puissance", false, false, 5, "Sur une attaque magique, le personnage peut utiliser un d12 en attaque au lieu du d20 habituel. Si l’attaque est réussie, il ajoute 2d6 aux DM. Cette capacité s’utilise uniquement avec les sorts nécessitant un test d’attaque et infligeant des DM. Si les DM sont répartis sur plusieurs tours, seuls les DM initiaux sont modifiés.")
        db.skillQueries.insert("Asphyxie", true, true, 1, "Si le magicien réussit son test d’attaque magique (avec une portée de 20 m), la créature ciblée est privée d’air. La victime étouffe progressivement et subit 1d6 DM par tour pendant [1+Mod. d’INT] tours.")
        db.skillQueries.insert("Protection contre les éléments", true, true, 2, "Pendant [5 + Mod. d’INT] tours, le personnage retranche à tous les DM de feu, de froid, d’électricité ou d’acide subis un montant égal à 2 fois son Rang dans cette Voie.")
        db.skillQueries.insert("Arme enflammée", true, true, 3, "Le personnage peut enflammer une arme pour [5 + Mod. d’INT] tours. Celle-ci inflige +1D6 DM de feu.")
        db.skillQueries.insert("Respiration aquatique", true, true, 4, "Le personnage peut respirer sous l’eau pendant 10 minutes. Cette capacité peut être étendue à un compagnon par point de Mod. d’INT.")
        db.skillQueries.insert("Peau de pierre", true, true, 5, "Le personnage obtient une réduction des DM égale à [5 + Mod. d’INT] pendant [5+ Mod. d’INT] tours ou jusqu’à ce que le sort ait absorbé 40 points de dégâts.")
        db.skillQueries.insert("Armure du mage", true, true, 1, "Le personnage fait apparaître un nuage magique argenté qui le protège contre les attaques adverses. Il bénéficie d’un bonus de +4 à la DEF pour le reste du combat. Si le sort est cumulé à une armure physique, le bonus est divisé par 2 (+2 DEF).")
        db.skillQueries.insert("Chute ralentie", true, true, 2, "Le personnage affecte une cible à moins de 10 mètres avec ce sort. La cible peut chuter de 6 mètres par rang dans la Voie sans subir de dégâts. Si la chute est supérieure à cette hauteur, elle est réduite d’autant.")
        db.skillQueries.insert("Flou", true, true, 3, "Pendant [1d4 + Mod. d’INT] tours, le corps du personnage devient flou et tous les DM des attaques de contact ou à distance qu’il encaisse sont divisés par 2.")
        db.skillQueries.insert("Cercle de protection", true, true, 4, "Le personnage peut tracer un cercle sur le sol pouvant contenir 3 personnes. Une fois par tour, lorsqu’un sort prend pour cible un personnage situé dans le cercle (par un test d’attaque magique), le personnage fait un test d’attaque magique en opposition à celui de l’adversaire. Si le test est réussi, le sort adverse est annulé et n’a aucun effet.")
        db.skillQueries.insert("Arrêt du temps", true, true, 5, "Le personnage arrête le temps pendant [1d6 + Mod. d’INT] tours. Seul le personnage peut agir à sa guise pendant cette période, lancer des sorts sur lui-même, se déplacer et déplacer des objets, tant qu’il ne touche pas un être vivant ou n’interagit pas avec lui (en lui lançant un sort par exemple). Dans le cas d’un contact (même magique), le temps reprend instantanément son cours normal.")
        db.skillQueries.insert("Lumière", true, true, 1, "Le personnage désigne un objet, lequel produit dès lors de la lumière dans un rayon de 20 mètres. Cette source de lumière n’émet pas de chaleur et s’éteint après 10 minutes ou lorsque le personnage le décide. Ce sort permet d’annuler un sort de Ténèbres lancé par un nécromancien de niveau inférieur.")
        db.skillQueries.insert("Détection de la magie", true, true, 2, "Le personnage se concentre et détecte la présence de toute inscription et de tout objet magique situé dans la pièce où il se trouve (ou dans les 15 mètres autour de lui). Ce sort permet aussi d’analyser les propriétés d’un objet magique au prix de 2 heures d’étude et de 100 pa de poudre d’argent.")
        db.skillQueries.insert("Invisibilité", true, true, 3, "Le personnage se rend invisible pendant [1d6 + Mod. d’INT] minutes. Une fois invisible, personne ne peut plus détecter sa présence ou lui porter d’attaque. Si le personnage attaque ou utilise une capacité limitée, il redevient visible.")
        db.skillQueries.insert("Vol", true, true, 4, "Le personnage peut voler pendant [1d6 + Mod. d’INT] minutes. Sa vitesse de déplacement est la même qu’au sol.")
        db.skillQueries.insert("Intelligence héroïque", false, false, 5, "Le personnage augmente sa valeur d’INT de +2 et il peut désormais lancer deux d20 à chaque fois qu’un test d’INT lui est demandé et conserver le meilleur résultat.")
        // le Moine
        db.skillQueries.insert("Mains d’énergie", true, false, 1, "Par un effort de concentration, le personnage peut rendre ses mains intangibles, à ce tour, il peut faire une attaque simple avec un bonus +2 en attaque, +5 si la cible porte une armure. De plus, toutes les attaques à mains nues du personnage sont considérées comme magiques (même lorsqu’il n’utilise pas Mains d’énergie).")
        db.skillQueries.insert("Pression mortelle", true, false, 2, "Le personnage frappe les points par lesquels circule l’énergie vitale d’une créature vivante. En touchant un point précis, il libère ensuite des effets dévastateurs. Lorsqu’il combat à mains nues, le joueur peut choisir de ne pas infliger immédiatement les DM de ses attaques. À tout moment dans l’heure qui suit, il peut annoncer une « Pression Mortelle ». Il doit alors réussir un test d’attaque contre la cible, ce qui libère instantanément la totalité des DM infligés jusqu’alors +1d6 DM supplémentaires.")
        db.skillQueries.insert("Invulnérable", false, false, 3, "Le personnage ne reçoit que la moitié des DM de toutes les sources «élémentaires» : feu, froid, foudre, acide... Il ne subit aucun DM des poisons ou des maladies.")
        db.skillQueries.insert("Projection du ki", true, false, 4, "Le personnage projette une vague de force avec son corps et son esprit à une distance maximum de 20 mètres. Un test d’attaque magique réussi (Mod. de SAG) lui permet d’infliger [2d6 + Mod. de SAG] de DM.")
        db.skillQueries.insert("Ascétisme", false, false, 5, "Le personnage peut subsister sans nourriture, sans eau et sans sommeil pendant [5 + Mod. SAG] jour. Il ne subit aucune pénalité durant cette période. De plus, il peut désormais lancer deux d20 à chaque fois qu’un test de CON lui est demandé et conserver le meilleur résultat.")
        db.skillQueries.insert("Esquive du singe", false, false, 1, "Pour chaque Rang dans cette Voie, le personnage gagne +1 en DEF et à tous ses tests de DEX pour effectuer des acrobaties.")
        db.skillQueries.insert("Morsure du serpent", false, false, 2, "Le personnage obtient des DM critiques (multipliés par 2) sur un résultat de 19 à 20 au d20 du test d’attaque à mains nues ou avec une arme de contact, et sur des résultats de 18 à 20 avec une rapière ou une Vivelame.")
        db.skillQueries.insert("Griffes du tigre", false, false, 3, "Les DM des attaques à mains nues du personnage sont désormais des jets sans limite : s’il obtient les DM maximum sur son dé, le joueur le relance et ajoute le nouveau résultat à ses DM. Tant que le dé donne le meilleur résultat possible, il est relancé et son score comptabilisé. Les dés en bonus (Puissance du Ki par exemple) ne sont jamais relancés, seulement ceux des DM à mains nues.")
        db.skillQueries.insert("Fureur du dragon", true, false, 4, "Une fois par combat, le personnage peut effectuer une attaque tournoyante qui inflige automatiquement [2d6+ Mod. de FOR] de DM à tous les adversaires au contact et oblige ceux-ci à réussir un test de FOR difficulté 10 pour ne pas tomber au sol.")
        db.skillQueries.insert("Moment de perfection", false, false, 5, "Une fois par combat, le personnage peut choisir de réussir toutes ses attaques automatiquement et d’esquiver toutes celles qui le prennent pour cible pendant un tour. Tout semble aller au ralenti autour de lui...")
        db.skillQueries.insert("Pacifisme", false, false, 1, "Tant que le personnage n’a réalisé aucune action offensive dans un combat, il bénéficie d’un bonus en DEF de +5.")
        db.skillQueries.insert("Transe de guérison", false, false, 2, "Une fois après chaque combat, le personnage peut méditer pendant 10 minutes et récupérer ainsi [niveau + Mod de SAG] PV.")
        db.skillQueries.insert("Maîtrise du ki", false, false, 3, "Le personnage utilise son intuition et son empathie avec le monde pour augmenter son efficacité en combat. Il ajoute son Mod. de SAG à son Initiative et sa DEF.")
        db.skillQueries.insert("Projection mentale", true, false, 4, "Le personnage entre en méditation et projette son esprit hors de son corps. Celui-ci ressemble à un ectoplasme de couleur blanche qui se déplace en volant à la vitesse de 10 m par tour. Il peut passer au travers des murs, mais pas des êtres vivants, et il reste relié à son corps d’origine par un long filin argenté. La durée maximum de la projection est de [valeur de SAG] tours. Le personnage ne perçoit le monde que via sa projection mentale mais ressent si des DM sont infligés à son corps.")
        db.skillQueries.insert("Sagesse héroïque", false, false, 5, "Le personnage augmente sa valeur de SAG de +2. Il peut désormais lancer deux d20 à chaque fois qu’un test de SAG lui est demandé et conserver le meilleur résultat.")
        db.skillQueries.insert("Poings de fer", false, false, 1, "Lorsqu’il combat à mains nues, le personnage peut (s’il le souhaite) utiliser son score d’attaque à distance au lieu de celui d’attaque au contact. Au rang 1 de cette voie, il inflige [1d6 + Mod. de FOR] DM létaux. Ces DM passent à 1d8 au Rang 3 et à 1d10 au rang 5.")
        db.skillQueries.insert("Parade de projectiles", false, false, 2, "Le personnage peut dévier un projectile (flèche, javelot,...) une fois par tour de combat (sauf si le test d’attaque est un critique ou si l’attaque vient d’une arme à poudre)...")
        db.skillQueries.insert("Peau de fer", false, false, 3, "Le personnage gagne un bonus de +2 en DEF.")
        db.skillQueries.insert("Déluge de coups", true, false, 4, "A son tour, le personnage peut effectuer 2 attaques à mains nues sur des cibles de son choix ou 2 attaques avec une arme. Alternativement, il peut choisir de faire 3 attaques en utilisant un d12 en attaque pour chacune d’elle (au lieu d’un d20).")
        db.skillQueries.insert("Puissance du ki", false, false, 5, "Le personnage peut choisir d’utiliser 1d12 en attaque au lieu du d20 habituel (et il ajoute normalement son score d’attaque). Si l’attaque est réussie, il ajoute 2d6 aux DM. Cette capacité peut être utilisée avec Déluge de coups ou Projection du ki par exemple.")
        db.skillQueries.insert("Pas du vent", false, false, 1, "Le personnage peut se déplacer avant et après avoir attaqué (mais il couvre toujours une distance normale). De plus, il gagne +1 par rang dans la Voie en Initiative.")
        db.skillQueries.insert("Course du vent", false, false, 2, "Le personnage se déplace à une vitesse surhumaine. Il couvre une distance de 40 mètres par action de mouvement (la distance normale est de 20 mètres) et se relever est pour lui une action gratuite.")
        db.skillQueries.insert("Course des airs", false, false, 3, "Le personnage défie les lois de la pesanteur et peut se déplacer sur des surfaces qui ne devraient pas supporter son poids. Il peut se déplacer sur l’eau, la neige, le feuillage des arbres ou courir sur un mur vertical. Il doit commencer et terminer son déplacement sur une surface normale.")
        db.skillQueries.insert("Lévitation", true, false, 4, "En se concentrant, le personnage peut « léviter » à une vitesse de 10 m par tour.")
        db.skillQueries.insert("Passe-muraille", true, false, 5, "Le personnage peut rendre son corps intangible temps de passer au travers d’un mur d’une épaisseur maximum de [Mod. de SAG] mètres. Il ne peut rester immatériel qu’un court instant et reprend corps dès qu’il émerge du mur. Il est insensible aux attaques tant qu’il est entièrement dans le mur, sauf si le mur est détruit.")
        // le Nécromancien
        db.skillQueries.insert("Malédiction", true, false, 1, "Effectuez un test d’attaque magique contre une cible à moins de 20 mètres. En cas de succès, la victime réalise tous ses tests avec deux d20 et garde le résultat le plus faible. Le sort prend fin dès qu’elle aura raté trois tests (il n’y a sinon aucune limite de temps). Si la cible possède une capacité lui permettant de lancer deux dés et de garder le meilleur, elle ne lance plus qu’un seul dé.")
        db.skillQueries.insert("Aspect de la succube", true, false, 2, "Le personnage acquiert une beauté fascinante pour [5 + Mod. d’INT] tours. Il gagne un bonus de +5 aux tests de CHA ainsi qu’une attaque de contact nécessitant un test d’attaque magique et qui inflige [1d4 + Mod. de CHA] DM. Ces DM sont transformés en PV, au bénéfice du personnage (sans dépasser son score max de PV).")
        db.skillQueries.insert("Pacte sanglant", false, false, 3, "Par une action gratuite, le personnage sacrifie 1d4 PV et gagne immédiatement +3 sur un jet de d20 de son choix ou en DEF contre une attaque. À partir du Rang 5 dans la voie, il peut sacrifier 2d4 PV pour faire passer ce bonus à +5.")
        db.skillQueries.insert("Aspect du démon", true, false, 4, "Le personnage prend l’apparence d’un démon pendant [5 + Mod. d’INT] tours. Il gagne + 2 en attaque au contact, en DEF et à tous les tests physiques (FOR, DEX, CON). Il peut faire deux attaques de griffe à 1d6+4 DM à chaque tour, en action limitée (une seule en action d’attaque). Ne se cumule pas avec l’Aspect de la succube.")
        db.skillQueries.insert("Invocation d’un démon", true, false, 5, "Une fois par combat, en sacrifiant 1d6 PV, le personnage invoque un démon à son service pour [5 + Mod. d’INT] tours. Ce démon possède l’apparence d’un Balor en plus petit (environ 2m30). Le démon divise par deux tous les DM non magiques subis, les sorts et les armes magiques lui infligent des DM normaux. Il est capable de voler à une vitesse équivalente à un déplacement normal. Lorsque le personnage atteint le niveau 10, le démon devient capable d’attaquer deux fois par tour, au prix d’une action limitée. Démon : FOR +5*, DEX +2, CON +4*, INT +2, SAG +2, CHA +0, Init 16, DEF 17, PV [niveau x 5], Attaque au contact = [niveau du nécromancien], DM 1d8+5")
        db.skillQueries.insert("Siphon des âmes", false, false, 1, "Chaque fois qu’une créature meurt à moins de 20 m du personnage, il récupère 1d6 PV.")
        db.skillQueries.insert("Masque mortuaire", true, false, 2, "Pendant [5 + Mod. d’INT] tours, le personnage prend l’apparence de la mort. Il est immunisé aux attaques qui n’affectent que les vivants et à la plupart des pouvoirs des mort-vivants (de plus, ceux-ci le prennent pour l’un des leurs). Il retranche 2 points à tous les DM physiques subits et divise par deux tous les DM de froid.")
        db.skillQueries.insert("Baiser du vampire", true, false, 3, "Ce sort nécessite la réussite d’un test d’attaque magique (portée 50 m). La cible subit [1d8+Mod. d’INT] DM et le personnage récupère autant de PV (sans dépasser son score max de PV).")
        db.skillQueries.insert("Briser les coeurs", true, false, 4, "Le personnage fait mine de broyer le coeur de sa victime. Il doit réussir une attaque magique (portée 20 m) et inflige [5d6 + Mod. d’INT] DM. La victime divise les DM par deux si elle réussit un test de CON difficulté [10 + Mod. d’INT].")
        db.skillQueries.insert("Mot de mort", true, false, 5, "Le personnage doit réussir un test d’attaque magique contre le score max de PV de sa cible (portée 10 m). La victime doit réussir un test de CON difficulté [ 10 + Mod. d’INT] ou tomber à 0 PV.")
        db.skillQueries.insert("Peur", true, false, 1, "Le personnage effectue un test d’attaque magique contre une cible (portée 20 m). Celle-ci doit réussir un test de FOR ou de SAG (au choix) difficulté [10 + Mod. d’INT] ou fuir pendant [1d4 + rang] tours (le MJ peut garder cette durée secrète). Une créature ne peut subir les effets de ce sort qu’une fois par combat.")
        db.skillQueries.insert("Animation des morts", true, false, 2, "Le personnage anime le cadavre d’un humanoïde de taille moyenne, décédé depuis moins d’une heure. Le zombi comprend les ordres « Attaquer », « Suivre », « Garder » et « Pas bouger ». Zombie : Init 8, DEF 10, PV 12, Att +3, DM 1d6+1, se déplace à 50% de la vitesse normale. Le zombi se dégrade et perd 1PV par minute. Le personnage peut contrôler un zombi par rang. Un zombi détruit tombe en poussière.")
        db.skillQueries.insert("Putréfaction", true, false, 3, "En réussissant un test d’attaque magique (portée 10 m), le personnage fait pourrir les chairs de sa victime, infligeant [1d6 + Mod. d’INT] DM. La victime subit un malus de -2 à tous ses tests pour le reste du combat, à moins de réussir un test de CON difficulté [12 + Mod. d’INT].")
        db.skillQueries.insert("Ensevelissement", true, false, 4, "Une fois par combat, si le personnage réussit un test d’attaque magique (portée 20 m), le sol s’ouvre sous les pieds d’une cible de taille moyenne et l’enterre vivante. Tant qu’elle est ensevelie, elle subit 2d6 DM par tour, ne peut agir ni être la cible d’attaques extérieures. À son tour, elle peut tenter de sortir de terre en réussissant un test de FOR ou de DEX (au choix) difficulté [13 + Mod. d’INT]. Si elle tombe à 0 PV, elle reste enterrée et décède au tour suivant. Chaque personne qui creuse pour l’aider lui octroie un bonus de +2 sur son test.")
        db.skillQueries.insert("Armée des morts", true, false, 5, "Une fois par jour, le personnage peut invoquer d’innombrables squelettes émergeant du sol pour attaquer ses ennemis pendant [niveau du nécromancien] tours. Les cibles situées dans un rayon de 20 m autour du personnage subissent automatiquement 3d6 DM par tour, à moins qu’elles n’utilisent une action limitée pour s’opposer aux squelettes (ce qui réduit les DM à 1d6). Les squelettes restent autour du personnage et se déplacent en même temps que lui dans une zone de 20 m de rayon. Tous les déplacements dans cette zone (même ceux des alliés) sont divisés par deux.")
        db.skillQueries.insert("Saignements", true, false, 1, "Le personnage doit réussir un test d’attaque magique (portée 10 m). Du sang s’écoule de la bouche, du nez, des oreilles et même des yeux de la victime, qui subit 1d6 DM par tour pendant [rang] tours.")
        db.skillQueries.insert("Sang mordant", true, false, 2, "Pendant [5 + Mod. d’INT] tours, le sang du personnage se transforme en un acide qui gicle lorsqu’il subit une blessure. Chaque fois qu’un ennemi au contact le blesse, ce dernier subit 1d6 DM d’acide.")
        db.skillQueries.insert("Exsangue", false, false, 3, "Lorsque le nécromant tombe à 0 PV, il peut continuer à agir mais avec un malus de -2 à tous ses tests. Une nouvelle attaque réussie infligeant au moins 1 point de DM finira par l’achever !")
        db.skillQueries.insert("Hémorragie", true, false, 4, "Si le personnage réussit un test d’attaque magique (portée 10 m), la victime saigne à la moindre blessure. Tous les DM des armes blanches infligées à la cible augmentent de 1d6 pendant [5 + Mod. d’INT] tours.")
        db.skillQueries.insert("Lien de sang", true, false, 5, "En réussissant un test d’attaque magique (portée 20 m), le personnage tisse un lien avec sa victime. Pendant [5 + Mod. de d’INT] tours, la moitié des DM reçus par le personnage sont également subis par la cible et le personnage peut lui lancer un sort sans la voir.")
        db.skillQueries.insert("Ténèbres", true, false, 1, "Le personnage invoque une zone fixe de ténèbres magiques, de 10 m de diamètre, pour une durée de [5 + Mod. d’INT] tours. Même les créatures capables de voir dans le noir sont aveuglées dans cette zone.")
        db.skillQueries.insert("Pattes d’araignée", true, false, 2, "Le personnage peut se déplacer de 10 m par action de mouvement sur les murs et les plafonds pendant [5 + Mod. d’INT] tours. S’il reste immobile, il peut lancer des sorts.")
        db.skillQueries.insert("Strangulation", true, false, 3, "En réussissant un test d’attaque magique (portée 20 m), le personnage étouffe une créature vivante et lui inflige [1d6 + Mod. d’INT] DM par tour pendant [rang] tours pourvu qu’il maintienne sa concentration par une action limitée. La victime subit un malus égal au nombre de tours d’effet de la Strangulation (-1 au premier tour, -2 au second, etc.) à tous ses tests. Si la victime sort du champ de vision du personnage, le sort prend fin.")
        db.skillQueries.insert("Ombre mortelle", true, false, 4, "L’ombre de la cible du personnage attaque son propriétaire pendant [3 + Mod. d’INT] tours (portée 20 m). L’ombre poursuit sa cible partout où elle se réfugie. Ombre : 1 attaque par tour, att = att de la cible, DM = DM de la cible divisés par 2.")
        db.skillQueries.insert("Intelligence héroïque", false, false, 5, "Le personnage augmente sa valeur d’INT de +2 et il peut désormais lancer deux d20 à chaque fois qu’un test d’INT lui est demandé et conserver le meilleur résultat.")
        // le Prêtre
        db.skillQueries.insert("Parole divine", false, false, 1, "Pour chaque rang dans cette Voie, le personnage obtient un bonus de +2 aux tests de CHA visant à convaincre ou convertir son auditoire.")
        db.skillQueries.insert("Arme d’argent", true, true, 2, "Ce miracle crée pour la durée du combat une arme d’argent et de lumière que seul le personnage peut utiliser. Cette arme inflige [1d6 + Mod. de SAG] de DM. Contre les démons et les mort-vivants, elle offre un bonus de +2 en attaque et ajoute +1d6 aux DM.")
        db.skillQueries.insert("Ailes célestes", true, true, 3, "Des ailes divines poussent dans le dos du personnage, qui peut voler à une vitesse équivalente à deux fois son déplacement normal pendant [5 + Mod. de SAG] tours. Rester en vol stationnaire avec les ailes céleste est une action de mouvement.")
        db.skillQueries.insert("Foudres divines", true, true, 4, "La foudre frappe toutes les créatures désignées dans un rayon de 10 mètres autour du personnage et leur inflige [1d6 + Mod. de SAG] de DM. Le personnage compare son test d’attaque magique à la DEF de chaque cible.")
        db.skillQueries.insert("Charisme héroïque", false, false, 5, "Le personnage augmente sa valeur de CHA de +2. Il peut de plus lancer deux d20 à chaque fois qu’un test de CHA lui est demandé et conserver le meilleur résultat.")
        db.skillQueries.insert("Arme bénie", false, false, 1, "Le personnage bénit son arme sacrée. S’il obtient un résultat de « 1 » sur son dé de DM, il relance le dé et garde le second résultat. Les DM de l’arme sont considérés comme magiques.")
        db.skillQueries.insert("Bouclier de la foi", false, false, 2, "Le personnage porte le symbole de sa foi sur son bouclier, ce qui lui confère un bonus supplémentaire de +1 en DEF. Ce bonus passe à +2 au Rang 4 de la Voie.")
        db.skillQueries.insert("Marteau spirituel", true, true, 3, "Le personnage effectue une attaque magique avec une portée de 30 mètres. Un projectile d’énergie prenant la forme de l’arme du personnage va percuter la cible, lui infligeant [1d8 + Mod. de SAG] de DM.")
        db.skillQueries.insert("Châtiment divin", true, false, 4, "Le personnage effectue une attaque de contact avec un bonus en attaque et aux dégâts égal à son Mod. de SAG.")
        db.skillQueries.insert("Mot de pouvoir", true, true, 5, "Une fois par combat, le personnage peut prononcer un mot avec la voix de son dieu. Cela dépasse l’entendement des mortels et ses ennemis à portée de vue sont paralysés de terreur pendant 1 tour tandis que tous ses alliés en vue bénéficient d’un bonus de +5 en attaque pendant cette période.")
        db.skillQueries.insert("Bénédiction", true, true, 1, "Le personnage entonne un chant pour encourager ses compagnons en vue. Ceux-ci (ainsi que le personnage) bénéficient d’un bonus de +1 à tous leurs tests de Caractéristique et d’attaque pendant [3 + Mod. de SAG] tours.")
        db.skillQueries.insert("Destruction des morts-vivants", true, true, 2, "Le personnage peut faire un test de SAG difficulté 13. S’il réussit, tous les morts-vivants en vue subissent 2d6 points de DM. Ces DM passent à 3d6 au rang 4 de la Voie.")
        db.skillQueries.insert("Sanctuaire", true, true, 3, "Quand le personnage lance ce sort, tous les adversaires qui veulent l’attaquer doivent d’abord réussir un test de SAG difficulté 15. S’ils échouent, ils ne peuvent pas l’attaquer. Les effets de ce sort durent [5 + Mod de SAG] tours, mais s’il tente la moindre attaque, le sort prend fin immédiatement.")
        db.skillQueries.insert("Intervention divine", false, false, 4, "Le personnage fait appel à son dieu pour changer le cours des événements. Une fois par combat, il peut décider qu’un test du MJ ou des joueurs est une réussite ou un échec, même après que les dés aient révélé leur résultat.")
        db.skillQueries.insert("Sagesse héroïque", false, false, 5, "Le personnage augmente sa valeur de SAG de +2. Il peut désormais lancer deux d20 à chaque fois qu’un test de SAG lui est demandé et conserver le meilleur résultat.")
        db.skillQueries.insert("Soins légers", true, true, 1, "Le personnage peut toucher une cible, qui récupère alors [1d8 + niveau du prêtre] PV perdus. Le personnage peut utiliser ce sort sur lui-même. Peut être utilisé un nombre de fois par jour égal au Rang que le personnage a atteint dans cette Voie.")
        db.skillQueries.insert("Soins modérés", true, true, 2, "Le personnage peut toucher une cible, qui récupère alors [2d8 + niveau du prêtre] PV perdus. Le personnage peut utiliser ce sort sur lui-même. Peut être utilisé un nombre de fois par jour égal au Rang que le personnage a atteint dans cette Voie.")
        db.skillQueries.insert("Soins de groupe", true, true, 3, "Une fois par combat, le personnage peut libérer une décharge d’énergie bienfaitrice : tous ses compagnons en vue et lui récupèrent [1d8 + niveau du prêtre] PV perdus.")
        db.skillQueries.insert("Guérison", true, true, 4, "Une fois par jour, le personnage peut toucher une cible, qui récupère alors tous ses PV perdus et se trouve guérie des poisons, maladies et affaiblissements de Caractéristiques.")
        db.skillQueries.insert("Rappel à la vie", false, true, 5, "Une fois par jour, le personnage peut rappeler à la vie un personnage décédé depuis moins de [Mod. de SAG du prêtre] heures par un rituel de 10 minutes. Il doit connaître personnellement la personne rappelée et posséder une relique lui appartenant. Le personnage revient à la conscience avec 1d6 PV.")
        db.skillQueries.insert("Vêtements sacrés", false, false, 1, "La tenue religieuse traditionnelle du personnage remplace une armure et a été bénie à cet effet : il obtient un bonus en DEF égal à +1 pour chaque Rang dans cette Voie (lorsqu’il ne porte aucune armure).")
        db.skillQueries.insert("Protection contre le mal", true, true, 2, "Le personnage peut lancer ce sort sur lui ou sur tout allié (portée : contact) pour la durée d’un combat. La cible obtient alors un bonus de +2 en DEF et pour tous les tests de résistance contre les attaques des mort-vivants, des démons, des élémentaires et des créatures conjurées (appelées d’un autre plan par magie).")
        db.skillQueries.insert("Délivrance", true, true, 3, "En touchant sa cible, le personnage annule les pénalités infligées par les sorts, les malédictions, la pétrification et les capacités spéciales d’autres personnages ou de créatures (douleur, mutilation, poisons etc.).")
        db.skillQueries.insert("Marche des plans", true, true, 4, "Une fois par jour et pour une durée maximale de [3 + Mod. de SAG] tours, le personnage peut passer dans une dimension entre les plans d’existence où le temps et l’espace sont déformés. Il se déplace dans une sorte de brouillard gris où le paysage défile à toute vitesse. Pour chaque tour de « Marche des plans », il se déplace en réalité de 10 km. Le lieu de sortie n’est cependant pas très précis et le MJ doit déterminer une position au hasard autour du point visé (à 1d6 km près).")
        db.skillQueries.insert("Messie", false, true, 5, "Une fois par aventure, le personnage entre directement en contact avec la puissance divine et réalise un miracle. Il s’agit d’un pouvoir extraordinaire que le MJ accorde au joueur et qui permet des actes légendaires comme écarter les eaux, téléporter tout son groupe ou invoquer des nuées mortelles...")
        // le Rôdeur
        db.skillQueries.insert("Sens affutés", false, false, 1, "Pour chaque Rang dans cette Voie, le personnage gagne un bonus de +2 à tous ses tests de SAG destinés à simuler la perception (vue, ouïe, vigilance, etc.). De plus, il ajoute son Mod. de SAG aux dégâts qu’il inflige à l’arc et à son Initiative.")
        db.skillQueries.insert("Tir aveugle", true, false, 2, "Le personnage peut attaquer à distance un ennemi qu'il ne voit pas (par exemple invisible ou plongé dans le noir total), mais dont il connaît l'existence et la direction approximative, comme s'il le voyait, donc sans le malus causé par le fait qu'il ne la voit pas.")
        db.skillQueries.insert("Tir rapide", true, false, 3, "Le personnage peut faire 2 attaques à distance pendant ce tour.")
        db.skillQueries.insert("Flèche de mort", true, false, 4, "Le personnage lance deux d20 pour son attaque et conserve le meilleur résultat. Les dégâts de la flèche sont doublés.")
        db.skillQueries.insert("Dans le mille", false, false, 5, "Pour une attaque à distance, le personnage peut choisir d’utiliser 1d12 en attaque au lieu du d20 habituel (et il ajoute normalement son score d’attaque à distance). Si l’attaque est réussie, il ajoute 2d6 aux DM. Cette Capacité peut être utilisée avec Tir Rapide ou Flèche de mort (le bonus de 2d6 aux DM n’est pas doublé) par exemple.")
        db.skillQueries.insert("Odorat", false, false, 1, "Le loup du personnage détecte les odeurs des animaux et des créatures là où ils sont passés. Le personnage obtient un bonus de +5 aux tests de SAG pour pister et suivre des traces.")
        db.skillQueries.insert("Surveillance", false, false, 2, "Le loup est constamment sur ses gardes. Le personnage a donc un temps d’avance quand des ennemis essaient de l’attaquer par surprise, il obtient un bonus de +5 pour les tests de surprise (SAG) et en Initiative. Lorsqu’il est surpris, il peut faire une attaque simple à distance AVANT que ne débute le premier tour de combat.")
        db.skillQueries.insert("Combat", false, false, 3, "Le loup du personnage peut désormais se battre comme un véritable personnage. Il attaque en même temps que le personnage. Loup : Init 13, DEF 14, PV [niveau x 4], attaque au contact = [niveau du personnage], DM 1d6+1, FOR +1, DEX +1, CON* +1, INT -3, SAG* +2, CHA -2.")
        db.skillQueries.insert("Empathie animale", true, false, 4, "Le personnage peut parler aux animaux. Il peut également communiquer avec son compagnon animal par télépathie et le guérir à distance en dépensant ses propres PV (1 PV du personnage pour 1 PV octroyé au compagnon animal).")
        db.skillQueries.insert("Animal fabuleux", false, false, 5, "Le loup du personnage devient un spécimen particulièrement puissant. Mâle alpha : Init 13, DEF 16, PV [niveau x 4], attaque au contact = [niveau du personnage+2], DM 1d6+3, FOR +3, DEX +1, CON* +3, INT -3, SAG* +2, CHA -2")
        db.skillQueries.insert("Chasseur émérite", false, false, 1, "Le personnage obtient un bonus de +2 en attaque et aux DM lorsqu’il combat des animaux et un bonus de +2 par Rang dans cette Voie pour pister ou retrouver des traces.")
        db.skillQueries.insert("Traquenard", true, false, 2, "Le personnage gagne un bonus de +2 en attaque et +2d6 aux DM sur sa première attaque contre une créature s’il possède un meilleur score d’Initiative.")
        db.skillQueries.insert("Attaque éclair", true, false, 3, "Le personnage peut effectuer une attaque au contact très percutante. Il ajoute son Mod. de DEX en attaque et aux DM pour cette offensive.")
        db.skillQueries.insert("Repli", true, false, 4, "Le personnage se déplace de 40 m en forêt en s’éloignant de ses ennemis. Le joueur fait un test de DEX difficulté 10, en cas de succès, il disparaît de la vue de ses poursuivants. Il peut s’éloigner ou rester caché sans risque d’être retrouvé ou rattrapé.")
        db.skillQueries.insert("Dextérité héroïque", false, false, 5, "Le personnage augmente son score de DEX de +2 et il peut désormais lancer deux d20 à chaque fois qu’un test de DEX lui est demandé, et conserver le meilleur résultat.")
        db.skillQueries.insert("Endurant", false, false, 1, "Pour chaque Rang dans cette Voie, le personnage obtient un bonus de +2 sur tous ses tests de CON destinés à résister à la fatigue, aux intempéries et liés de manière générale à la survie en milieu naturel.")
        db.skillQueries.insert("Nature nourricière", false, false, 2, "Si le personnage passe 1 heure en forêt, il trouve de quoi nourrir deux personnes (pour une journée) pour chaque rang qu’il possède dans cette voie. En passant 1d6 heure(s) et en réussissant un test de SAG difficulté 10, le personnage trouve des plantes médicinales qui lui permettent de soigner 1d6 PV par Rang. Ces plantes doivent être utilisées immédiatement. Ces soins peuvent toutefois être répartis sur plusieurs patients : le joueur alloue les d6 correspondant aux plantes médicinales à sa guise.")
        db.skillQueries.insert("Grand pas", false, false, 3, "Le personnage augmente tous ses déplacements de 10 m. Il n’est pas gêné par les terrains accidentés et obtient +5 aux tests de natation et d’escalade.")
        db.skillQueries.insert("Increvable", true, false, 4, "Si vous croyez en avoir fini avec lui... Une fois par combat, lorsqu’il tombe à 0 PV, le personnage peut récupérer [3d6 + Mod. de CON] PV au tour suivant.")
        db.skillQueries.insert("Constitution héroïque", false, false, 5, "Le personnage augmente son score de CON de +2 et il peut désormais lancer deux d20 à chaque fois qu’un test de CON lui est demandé et conserver le meilleur résultat.")
        db.skillQueries.insert("Pas de loup", false, false, 1, "Quand il essaie de passer inaperçu en forêt, le personnage bénéficie d’un bonus de +2 par Rang à son test de DEX.")
        db.skillQueries.insert("Ennemi juré", false, false, 2, "Après avoir tué une créature, le personnage peut décider que tous ceux de sa race sont devenus des ennemis jurés. Contre ces créatures, il bénéficie d’un bonus égal à son Mod. de SAG pour ses attaques et il inflige +1d6 de DM. Le personnage peut changer d’ennemi juré une fois au cours de chaque niveau.")
        db.skillQueries.insert("Embuscade", false, false, 3, "En quelques minutes, le personnage peut cacher tous ses compagnons dans n’importe quel environnement naturel. Tant qu’ils ne bougent pas, le personnage et ses compagnons sont totalement indétectables. S’ils attaquent des adversaires, ces derniers sont automatiquement Surpris lors du premier tour du combat.")
        db.skillQueries.insert("Second ennemi juré", false, false, 4, "Le personnage choisit une nouvelle race ennemie. Les règles et avantages de la capacité Ennemi juré s’appliquent à l’identique.")
        db.skillQueries.insert("Perception héroïque", false, false, 5, "Le personnage augmente sa valeur de SAG de +2 et il peut désormais lancer deux d20 à chaque fois qu’un test de SAG lui est demandé et conserver le meilleur résultat.")
//        db.skillQueries.insert("Impressionnant", false, false, 1, "L’ours n’est pas dressé à attaquer, mais les interlocuteurs du personnage ne le savent pas, aussi gagne-t-il un bonus de +5 à tous ses tests d’intimidation lorsque l’animal est à ses cotés. L’ours n’attaque que pour se défendre s’il est blessé.")
//        db.skillQueries.insert("Dressage", false, false, 2, "Le personnage a dressé l’ours, il peut lui faire faire des numéros comme marcher sur les pattes avant ou porter un objet en équilibre sur son museau, cela peut lui permettre de gagner un peu d’argent dans les villages (2d6 pa en 2d6 minutes). Il peut aussi faire croire que l’ours l’attaque et simuler un combat.")
//        db.skillQueries.insert("Combat", false, false, 3, "L’ours du personnage peut désormais se battre comme un véritable personnage. Il attaque en même temps que le personnage. Jeune ours noir : Init 13, DEF 14, PV [niveau x 5], attaque au contact = [niveau du personnage], DM 1d6+3, FOR +3*, DEX +1, CON +3, INT -4, SAG +2, CHA -2")
//        db.skillQueries.insert("Empathie animale", true, false, 4, "Le personnage peut parler aux animaux. Il peut également communiquer avec son compagnon animal par télépathie et le guérir à distance en dépensant ses propres PV (1 PV du personnage pour 1 PV octroyé au compagnon animal).")
//        db.skillQueries.insert("Animal fabuleux", false, false, 5, "L’ours du personnage devient un spécimen en pleine possession de ses moyens. Ours noir : Init 15, DEF 17, PV [niveau x 5], attaque au contact = [niveau du rôdeur+2], DM 1d6+5, FOR +5*, DEX +2, CON +5, INT -4, SAG +2, CHA -2")
        // le Voleur
        db.skillQueries.insert("Discrétion", false, false, 1, "Quand il essaie de passer inaperçu, le personnage bénéficie d’un bonus de +2 à son test de DEX pour chaque rang acquis dans cette voie.")
        db.skillQueries.insert("Attaque sournoise", true, false, 2, "Quand il attaque un adversaire Surpris ou dans le dos*, le personnage inflige 2d6 de DM supplémentaires (notez que les dés bonus ne sont pas multipliés en cas de critique). Les DM infligés par cette capacité augmentent de +1d6 à chaque fois que le personnage atteint le rang 4 dans une Voie du voleur.\n    * Attaquer de dos : lorsque le personnage attaque la même créature qu’un allié, on considère qu’il peut attaquer celle-ci de dos à 2 conditions :\n    1. Le personnage et l’allié peuvent se placer de part et d’autre de la cible.\n    2. La cible n’a pas attaqué le personnage à son dernier tour (dans le cas contraire, on considère qu’elle lui fait face).")
        db.skillQueries.insert("Ombre mouvante", true, false, 3, "En réussissant un test de DEX difficulté 10, le personnage peut disparaître dans les ombres à son tour et ne réapparaître qu’au tour suivant durant sa phase d’Initiative. Aucun adversaire ne peut l’attaquer pendant qu’il a disparu dans les ombres, mais il peut subir des DM de zone. Le personnage réapparait à une distance maximum de 10 m de sa position initiale, si le personnage a l’Initiative, il peut réaliser une Attaque sournoise.")
        db.skillQueries.insert("Surprise", false, false, 4, "Le personnage n’est jamais surpris. Il peut réaliser une Attaque sournoise en utilisant une action d’attaque plutôt qu’une action limitée contre un adversaire Surpris.")
        db.skillQueries.insert("Ouverture mortelle", false, false, 5, "Une fois par combat, le personnage obtient une réussite critique automatique contre la cible de son choix. Il profite donc d’une réussite automatique, des dégâts multipliés par 2 prévus dans ce cas, et même des d6 d’Attaque sournoise, eux aussi multipliés.")
        db.skillQueries.insert("Sprint", false, false, 1, "Une fois par combat, le personnage peut effectuer un déplacement supplémentaire gratuit de 20 mètres à n’importe quel moment du tour.")
        db.skillQueries.insert("Provocation", true, false, 2, "Le personnage maîtrise l’art de se rendre désagréable, voire insupportable. Par un test opposé de CHA contre l’INT de la victime, il peut forcer celle-ci à l’attaquer pendant ce tour. Le personnage peut immédiatement riposter par une attaque gratuite ou, si la cible l’a raté, par une attaque sournoise !")
        db.skillQueries.insert("Grâce féline", false, false, 3, "Le personnage possède une démarche et une façon de se déplacer à la fois élégante, féline et souple. Il gagne son Mod. de CHA en Initiative, en DEF et à tous les tests de DEX en rapport avec le déplacement (escalade, saut, course, acrobaties, etc.).")
        db.skillQueries.insert("Feindre la mort", false, false, 4, "Une fois par combat, le personnage peut feindre la mort après avoir reçu une blessure (même à 0 PV). Il peut ainsi passer pour mort aussi longtemps qu’il le souhaite et un test d’INT difficulté 20 est nécessaire pour révéler la supercherie. Lorsqu’il décide de se relever, le personnage gagne +1d6 PV et il obtient une action de mouvement supplémentaire en plus des actions normales autorisées à son tour.")
        db.skillQueries.insert("Charisme héroïque", false, false, 5, "Le personnage augmente sa valeur de CHA de +2. Il peut de plus lancer deux d20 à chaque fois qu’un test de CHA lui est demandé et conserver le meilleur résultat.")
        db.skillQueries.insert("Esquive", false, false, 1, "Le personnage est très vif et bénéficie d’un bonus de +1 par rang dans cette voie à sa DEF et à tous ses tests de DEX destinés à esquiver.")
        db.skillQueries.insert("Chute", false, false, 2, "Le personnage peut tomber d’une hauteur de 3 m par rang sans se faire mal (rappel : un personnage qui n 'a pas cette capacité subit 1d6 points de dégâts tous les 3 m de chute - Règles des chutes).")
        db.skillQueries.insert("Acrobaties", false, false, 3, "Si le personnage réussit un test de DEX difficulté 15, il peut effectuer une acrobatie pour franchir un obstacle ou, s’il est au combat au contact, pour surprendre son adversaire par une cabriole, ce qui lui permet de l’attaquer dans le dos (et d’utiliser l’Attaque sournoise).")
        db.skillQueries.insert("Esquive de la magie", false, false, 4, "À chaque fois qu’un sort le prend pour cible (y compris un sort de zone ou l’affectant en plus de la personne visée), le personnage peut effectuer un test de DEX en opposition au test d’attaque magique du sort. S’il réussit, il échappe au sort. S’il échoue, tous les effets du sort (puissance, durée, etc.) sont divisés par 2. Au cas où un autre effet diviserait déjà les DM par 2, ils seront au total divisés par 4.")
        db.skillQueries.insert("Dextérité héroïque", false, false, 5, "Le personnage augmente son score de DEX de +2 et il peut désormais lancer deux d20 à chaque fois qu’un test de DEX lui est demandé, et conserver le meilleur résultat.")
        db.skillQueries.insert("Doigts agiles", false, false, 1, "Pour chaque Rang acquis dans cette Voie, le personnage reçoit un bonus de +2 pour tous ses tests de DEX liés à la précision : crocheter une serrure, désamorcer un piège, pickpocket...")
        db.skillQueries.insert("Détecter les pièges", false, false, 2, "En réussissant un test d’INT difficulté 10, le personnage peut détecter (et ensuite contourner sans danger) les pièges (avant qu’ils ne se déclenchent bien entendu). Les pièges magiques demandent un test d’INT de difficulté 15.")
        db.skillQueries.insert("Croc-en-jambe", false, false, 3, "Lorsqu’il obtient un score de 17 à 20 sur son d20 en attaque au contact, le personnage fait chuter son adversaire en plus de lui infliger des DM normaux. Un score de 19 à 20 est nécessaire pour une créature quadrupède.")
        db.skillQueries.insert("Attaque paralysante", true, false, 4, "Une fois par combat, le personnage peut, en réussissant une attaque de contact, paralyser un adversaire de douleur. Ce dernier n’encaisse pas de DM, mais il ne peut plus attaquer ni se déplacer pendant 1d4 tours.")
        db.skillQueries.insert("Attaque en traître", false, false, 5, "Une fois par tour, lorsqu’un allié réussit à blesser une créature au contact du personnage, celui-ci peut lui porter une attaque normale gratuite en profitant de l’ouverture.")
        db.skillQueries.insert("Attaque en finesse", false, false, 1, "Le personnage peut utiliser son score d’Attaque à distance pour une attaque au contact lorsqu’il utilise une arme légère comme une dague ou une rapière. S’il le souhaite, il peut dans ce cas remplacer le Mod. de FOR aux DM par son Mod. d’INT.")
        db.skillQueries.insert("Esquive fatale", false, false, 2, "Une fois par combat, le duelliste peut esquiver une attaque qui devait le toucher et s’arranger pour que celle-ci affecte un autre adversaire à son contact. Comparez le test d’attaque à la DEF de la nouvelle cible pour savoir si celle-ci subit des DM.")
        db.skillQueries.insert("Frappe chirurgicale", false, false, 3, "Par sa science de l’escrime (et de la fourberie), le personnage augmente de manière permanente ses chances de faire des coups critiques. Il retranche désormais son Mod. d’INT au score nécessaire pour obtenir un critique en attaque au contact. Par exemple, Alonzo (INT 14/+2) obtient à présent un critique sur 17 ou plus au d20 lorsqu’il emploie la rapière (19 – Mod. d’INT).")
        db.skillQueries.insert("Ambidextrie", false, false, 4, "Le personnage peut à présent utiliser une arme dans chaque main sans pénalité. Avec sa main gauche, il peut effectuer une attaque au contact gratuite supplémentaire à chaque tour. Cette deuxième attaque n’empêche pas l’utilisation d’une capacité limitée, mais elle ne peut pas en être l’origine.")
        db.skillQueries.insert("Botte secrète", false, false, 5, "Lorsque le personnage obtient un critique sur une attaque au contact, l’attaque devient automatiquement une Attaque sournoise. Les effets de la capacité d’Attaque sournoise s’appliquent en plus des effets normaux du critique.")
